export enum EmployeeStatus {
  ACTIVE = 'Active',
  RESIGNED = 'Resigned',
  SUSPENDED = 'Suspended',
  ON_LEAVE = 'On Leave'
}

export interface Employee {
  id: string;
  firstName: string;
  lastName: string;
  email: string;
  designation: string;
  department: string;
  basicSalary: number; // Annual or Monthly? Let's assume Monthly Basic for simplicity in this demo model
  housingAllowance: number;
  transportAllowance: number;
  pfa: string; // Pension Fund Administrator
  rsaNumber: string; // Retirement Savings Account
  status: EmployeeStatus;
  joinDate: string;
  cooperativeLoanBalance: number;
}

export interface PayrollEntry {
  employeeId: string;
  employeeName: string;
  employeeStatus: EmployeeStatus;
  basic: number;
  housing: number;
  transport: number;
  grossIncome: number;
  overtime: number;
  bonuses: number;

  // Deductions
  pensionEmployee: number; // 8%
  pensionEmployer: number; // 10%
  taxPAYE: number;
  loanDeduction: number;
  otherDeductions: number;

  totalDeductions: number;
  netPay: number;
}

export interface PayrollRun {
  id: string;
  month: string; // YYYY-MM
  status: 'Draft' | 'Finalized';
  entries: PayrollEntry[];
  totalPayout: number;
  totalTax: number;
  totalPension: number;
  dateCreated: string;
}

export interface TaxBand {
  limit: number;
  rate: number;
}

// Nigerian PAYE Bands (Annualized simplified)
export const TAX_BANDS: TaxBand[] = [
  { limit: 300000, rate: 0.07 },
  { limit: 300000, rate: 0.11 },
  { limit: 500000, rate: 0.15 },
  { limit: 500000, rate: 0.19 },
  { limit: 1600000, rate: 0.21 },
  { limit: Infinity, rate: 0.24 } // 3.2M and above
];

import { Employee, PayrollEntry, TAX_BANDS } from '../types';

/**
 * Calculates the monthly PAYE tax based on Nigerian Personal Income Tax Act (PITA).
 * Note: PITA is annual, so we annualize monthly figures, calculate annual tax, then divide by 12.
 */
export const calculatePAYE = (grossMonthly: number, pensionMonthly: number, nhfMonthly: number = 0): number => {
  const grossAnnual = grossMonthly * 12;
  const pensionAnnual = pensionMonthly * 12;
  const nhfAnnual = nhfMonthly * 12;

  // Consolidated Relief Allowance (CRA)
  // Higher of 200k or 1% of Gross Annual Income, PLUS 20% of Gross Annual Income
  const baseRelief = Math.max(200000, grossAnnual * 0.01);
  const percentageRelief = grossAnnual * 0.20;
  const cra = baseRelief + percentageRelief;

  // Tax Exempt Items
  const taxExempt = pensionAnnual + nhfAnnual + cra;

  // Chargeable Income
  let chargeableIncome = grossAnnual - taxExempt;

  if (chargeableIncome <= 0) {
    // Minimum Tax Rule: 1% of Gross Income if taxable income is too low (Simplified rule)
    // For this demo, let's just say 0 if negative.
    return Math.max(0, (grossAnnual * 0.01) / 12); 
  }

  let totalTax = 0;
  let remainingIncome = chargeableIncome;

  for (const band of TAX_BANDS) {
    if (remainingIncome <= 0) break;

    const taxableAmount = Math.min(remainingIncome, band.limit);
    totalTax += taxableAmount * band.rate;
    remainingIncome -= taxableAmount;
  }

  return totalTax / 12;
};

export const calculatePayrollEntry = (
  employee: Employee, 
  overtime: number = 0, 
  bonus: number = 0,
  loanRepayment: number = 0
): PayrollEntry => {

  // 1. Gross Calculation
  const fixedAllowances = employee.housingAllowance + employee.transportAllowance;
  const grossIncome = employee.basicSalary + fixedAllowances + overtime + bonus;

  // 2. Pension (8% of Basic + Housing + Transport) - Strictly strictly usually Basic+Housing+Transport in practice
  // Some companies do on Basic only, but standard is BHT.
  const pensionableEmolument = employee.basicSalary + employee.housingAllowance + employee.transportAllowance;
  const pensionEmployee = pensionableEmolument * 0.08;
  const pensionEmployer = pensionableEmolument * 0.10;

  // 3. Tax
  const taxPAYE = calculatePAYE(grossIncome, pensionEmployee);

  // 4. Other Deductions
  const loanDeduction = Math.min(loanRepayment, employee.cooperativeLoanBalance); // Cannot deduct more than balance

  const totalDeductions = pensionEmployee + taxPAYE + loanDeduction;
  const netPay = grossIncome - totalDeductions;

  return {
    employeeId: employee.id,
    employeeName: `${employee.firstName} ${employee.lastName}`,
    employeeStatus: employee.status,
    basic: employee.basicSalary,
    housing: employee.housingAllowance,
    transport: employee.transportAllowance,
    grossIncome,
    overtime,
    bonuses: bonus,
    pensionEmployee,
    pensionEmployer,
    taxPAYE,
    loanDeduction,
    otherDeductions: 0,
    totalDeductions,
    netPay
  };
};

import { GoogleGenAI } from "@google/genai";
import { PayrollRun, EmployeeStatus } from '../types';

export const analyzePayroll = async (payrollRun: PayrollRun) => {
  if (!process.env.API_KEY) {
    console.warn("API Key is missing for Gemini");
    return "API Key missing. Cannot perform AI audit.";
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Prepare a summarized version of data to save tokens and focus attention
  const summaryData = {
    month: payrollRun.month,
    totalStaff: payrollRun.entries.length,
    totalPayout: payrollRun.totalPayout,
    entries: payrollRun.entries.map(e => ({
      name: e.employeeName,
      status: e.employeeStatus,
      netPay: e.netPay,
      tax: e.taxPAYE,
      pension: e.pensionEmployee,
      loanPaid: e.loanDeduction,
      overtime: e.overtime
    }))
  };

  const prompt = `
    You are an expert HR and Payroll Auditor for a Nigerian manufacturing company.
    Analyze the following payroll run data for compliance and anomalies.

    Specific things to check:
    1. **Ghost Workers**: Are there any employees with status '${EmployeeStatus.RESIGNED}' or '${EmployeeStatus.SUSPENDED}' who are receiving a Net Pay > 0? This is critical.
    2. **Unusual Overtime**: Flag any employee earning overtime that is more than 50% of their basic salary (Assume basic is roughly 40% of gross for this check if not provided explicitly, but look at the overtime values).
    3. **Tax/Pension Compliance**: Briefly confirm if tax and pension seem to be calculated (non-zero) for active employees.
    4. **Loan Deductions**: Note if many employees are paying back loans.

    Provide a concise, professional report in Markdown format. Use bullet points for issues found.
    If everything looks good, state that the payroll appears clean.

    Payroll Data:
    ${JSON.stringify(summaryData)}
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 0 } // Speed over deep thought for this
      }
    });

    return response.text;
  } catch (error) {
    console.error("Gemini Audit Error:", error);
    return "An error occurred while communicating with the AI Auditor.";
  }
};

export const askPayrollAssistant = async (question: string, contextData: any) => {
   if (!process.env.API_KEY) {
    return "API Key missing.";
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    You are an expert Payroll Assistant for a Nigerian company.
    Context Data (Current Payroll/Employee Stats): ${JSON.stringify(contextData)}

    User Question: ${question}

    Answer clearly and concisely. If it involves tax law, refer to Nigerian PITA.
  `;

  try {
    const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt
    });
    return response.text;
  } catch (error) {
      return "I couldn't process your request at this time.";
  }
}

