                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">Housing Allowance (₦)</label>
                <input 
                  type="number" 
                  className="w-full border p-2 rounded" 
                  value={formData.housingAllowance}
                  onChange={e => setFormData({...formData, housingAllowance: Number(e.target.value)})}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">Transport Allowance (₦)</label>
                <input 
                  type="number" 
                  className="w-full border p-2 rounded" 
                  value={formData.transportAllowance}
                  onChange={e => setFormData({...formData, transportAllowance: Number(e.target.value)})}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">Cooperative Loan Bal (₦)</label>
                <input 
                  type="number" 
                  className="w-full border p-2 rounded" 
                  value={formData.cooperativeLoanBalance}
                  onChange={e => setFormData({...formData, cooperativeLoanBalance: Number(e.target.value)})}
                />
              </div>

               <div className="col-span-2 mt-2 pt-2 border-t border-slate-100">
                <h4 className="font-semibold text-sm text-slate-900 mb-2">Compliance</h4>
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">PFA Name</label>
                <select 
                  className="w-full border p-2 rounded"
                  value={formData.pfa}
                  onChange={e => setFormData({...formData, pfa: e.target.value})}
                >
                  <option>Stanbic IBTC Pension Managers</option>
                  <option>ARM Pension Managers</option>
                  <option>Leadway Pensure</option>
                  <option>Fidelity Pension</option>
                  <option>Premium Pension</option>
                </select>
              </div>
               <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">RSA Number</label>
                <input 
                  type="text" 
                  className="w-full border p-2 rounded" 
                  value={formData.rsaNumber}
                  onChange={e => setFormData({...formData, rsaNumber: e.target.value})}
                />
              </div>
            </div>

            <div className="mt-6 flex justify-end gap-3">
              <button 
                onClick={() => setShowModal(false)}
                className="px-4 py-2 text-slate-600 hover:bg-slate-100 rounded-lg"
              >
                Cancel
              </button>
              <button 
                onClick={handleSave}
                className="px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 shadow"
              >
                Save Employee
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Biometric Enrollment Modal */}
      {showBiometricModal && editingEmployee && (
         <div className="fixed inset-0 bg-black/80 flex items-center justify-center z-[60]">
            <div className="bg-white rounded-xl shadow-2xl overflow-hidden w-full max-w-md">
               <div className="p-6 text-center">
                 <div className="w-16 h-16 bg-blue-50 rounded-full flex items-center justify-center mx-auto mb-4 text-blue-600">
                   <ScanFace size={32} />
                 </div>
                 <h3 className="text-xl font-bold text-slate-900">Enroll Face Biometrics</h3>
                 <p className="text-slate-500 text-sm mt-1">
                   {biometricStep === 'success' 
                     ? `Verified ${editingEmployee.firstName}'s Identity`
                     : `Verify identity for ${editingEmployee.firstName} ${editingEmployee.lastName}`}
                 </p>
               </div>

               <div className="px-6 pb-6">
                 {biometricStep === 'start' && (
                   <div className="space-y-3">
                      <button 
                        onClick={startCamera}
                        className="w-full py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-medium flex items-center justify-center gap-2 transition"
                      >
                        <Camera size={20} /> Use Camera
                      </button>
                      <div className="relative">
                        <input 
                          type="file" 
                          accept="image/*" 
                          className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                          onChange={handleFileUpload}
                        />
                         <button 
                          className="w-full py-3 bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-lg font-medium flex items-center justify-center gap-2 transition"
                        >
                          <Upload size={20} /> Upload Photo
                        </button>
                      </div>
                   </div>
                 )}

                 {biometricStep === 'scanning' && (
                   <div className="relative bg-black rounded-lg overflow-hidden aspect-square mb-4">
                     <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover"></video>
                     <div className="absolute inset-0 border-2 border-blue-500/50 rounded-lg"></div>
                     <div className="absolute inset-0 flex items-center justify-center">
                       <div className="w-48 h-48 border-2 border-dashed border-white/50 rounded-full"></div>
                     </div>
                     <button 
                        onClick={captureAndVerify}
                        className="absolute bottom-4 left-1/2 -translate-x-1/2 bg-white/20 backdrop-blur text-white px-6 py-2 rounded-full font-bold hover:bg-white/30 transition border border-white/50"
                      >
                        Capture & Verify
                      </button>
                   </div>
                 )}

                 {biometricStep === 'processing' && (
                   <div className="py-12 flex flex-col items-center">
                      <div className="w-12 h-12 border-4 border-blue-200 border-t-blue-600 rounded-full animate-spin mb-4"></div>
                      <p className="text-slate-600 font-medium">Processing biometrics...</p>
                      <p className="text-xs text-slate-400 mt-1">Creating secure hash</p>
                   </div>
                 )}

                 {biometricStep === 'success' && (
                   <div className="py-8 flex flex-col items-center">
                      <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center text-green-600 mb-4 animate-bounce">
                        <CheckCircle size={32} />
                      </div>
                      <h4 className="text-lg font-bold text-slate-800">Enrollment Successful</h4>
                      <p className="text-sm text-slate-500 text-center mt-2">
                        Employee biometrics have been securely linked to their profile.
                      </p>
                      <button 
                        onClick={closeBiometricModal}
                        className="mt-6 w-full py-2 bg-slate-900 text-white rounded-lg hover:bg-slate-800"
                      >
                        Close
                      </button>
                   </div>
                 )}
               </div>

               {biometricStep === 'start' && (
                 <button onClick={closeBiometricModal} className="absolute top-4 right-4 text-slate-400 hover:text-slate-600">
                   <X size={20} />
                 </button>
               )}
            </div>
         </div>
      )}
    </div>
  );
};

export default EmployeeManager;

import React, { useState, useEffect } from 'react';
import { Employee, EmployeeStatus, PayrollRun, PayrollEntry } from '../types';
import { calculatePayrollEntry } from '../services/payrollUtils';
import { Play, Save, Download, RefreshCw, AlertCircle, ScanFace, ShieldAlert } from 'lucide-react';

interface PayrollProcessorProps {
  employees: Employee[];
  payrollRuns: PayrollRun[];
  setPayrollRuns: React.Dispatch<React.SetStateAction<PayrollRun[]>>;
}

const PayrollProcessor: React.FC<PayrollProcessorProps> = ({ employees, payrollRuns, setPayrollRuns }) => {
  const [selectedMonth, setSelectedMonth] = useState('2023-11');
  const [currentRun, setCurrentRun] = useState<PayrollRun | null>(null);

  // Local state for variable inputs before calculation
  const [variableInputs, setVariableInputs] = useState<Record<string, { overtime: number, bonus: number, loanPaid: number }>>({});

  useEffect(() => {
    // Check if run exists
    const existingRun = payrollRuns.find(r => r.month === selectedMonth);
    setCurrentRun(existingRun || null);
  }, [selectedMonth, payrollRuns]);

  const handleGenerateDraft = () => {
    const entries: PayrollEntry[] = employees.map(emp => {
      // Skip suspended or resigned if needed, OR include them but alert. 
      // Requirement: Prevent ghost workers.
      // Strategy: Include them in the draft but highlight them if Net Pay > 0 when status is Resigned.

      const inputs = variableInputs[emp.id] || { overtime: 0, bonus: 0, loanPaid: 0 };

      // Auto-deduct loan if they have balance, up to a limit (e.g. 33% of basic) or use manual input
      // For this demo, let's assume default loan deduction is 0 unless manually entered or auto-calculated elsewhere.
      // We will use the manual input 'loanPaid'.

      return calculatePayrollEntry(emp, inputs.overtime, inputs.bonus, inputs.loanPaid);
    });

    const totalPayout = entries.reduce((acc, curr) => acc + curr.netPay, 0);
    const totalTax = entries.reduce((acc, curr) => acc + curr.taxPAYE, 0);
    const totalPension = entries.reduce((acc, curr) => acc + curr.pensionEmployee + curr.pensionEmployer, 0);

    const newRun: PayrollRun = {
      id: crypto.randomUUID(),
      month: selectedMonth,
      status: 'Draft',
      entries,
      totalPayout,
      totalTax,
      totalPension,
      dateCreated: new Date().toISOString()
    };

    setCurrentRun(newRun);
  };

  const handleFinalize = () => {
    if (!currentRun) return;

    // Check for biometric flags
    const hasUnverified = currentRun.entries.some(e => !e.isBiometricVerified && e.employeeStatus === EmployeeStatus.ACTIVE);
    if(hasUnverified) {
      if(!confirm("Warning: Some active employees have NOT completed biometric verification. Are you sure you want to finalize payment?")) {
        return;
      }
    }

    const finalRun = { ...currentRun, status: 'Finalized' as const };

    // Update main state
    const otherRuns = payrollRuns.filter(r => r.month !== selectedMonth);
    setPayrollRuns([...otherRuns, finalRun]);
    setCurrentRun(finalRun);

    // In a real app, update employee loan balances here
    alert("Payroll finalized successfully!");
  };

  const updateVariableInput = (id: string, field: 'overtime' | 'bonus' | 'loanPaid', value: number) => {
    setVariableInputs(prev => ({
      ...prev,
      [id]: {
        ...prev[id] || { overtime: 0, bonus: 0, loanPaid: 0 },
        [field]: value
      }
    }));
  };

  return (
    <div className="p-6">
       <div className="flex justify-between items-center mb-6">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Run Payroll</h2>
          <p className="text-slate-500">Calculate salaries, taxes, and deductions for {selectedMonth}.</p>
        </div>
        <div className="flex items-center gap-3">
            <input 
              type="month" 
              className="border p-2 rounded-lg bg-white"
              value={selectedMonth}
              onChange={(e) => setSelectedMonth(e.target.value)}
            />
            {(!currentRun || currentRun.status === 'Draft') && (
              <button 
                onClick={handleGenerateDraft}
                className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition shadow"
              >
                <RefreshCw size={18} /> {currentRun ? 'Recalculate Draft' : 'Generate Draft'}
              </button>
            )}
            {currentRun?.status === 'Draft' && (
              <button 
                onClick={handleFinalize}
                className="bg-green-600 hover:bg-green-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition shadow"
              >
                <Save size={18} /> Finalize Payroll
              </button>
            )}
            {currentRun?.status === 'Finalized' && (
              <button className="bg-slate-800 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition shadow cursor-not-allowed opacity-80">
                <Save size={18} /> Finalized
              </button>
            )}
        </div>
      </div>

      {!currentRun && (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-12 flex flex-col items-center justify-center text-center">
            <div className="bg-blue-50 p-4 rounded-full text-blue-500 mb-4">
              <Play size={32} />
            </div>
            <h3 className="text-lg font-semibold text-slate-800">Ready to Process</h3>
            <p className="text-slate-500 max-w-md mt-2">
              Select a month and click "Generate Draft" to start the payroll calculation engine. 
              The system will automatically compute PAYE, Pension, and Deductions.
            </p>
        </div>
      )}

      {currentRun && (
        <div className="space-y-6">
          {/* Summary Cards */}
          <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
            <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
              <p className="text-sm text-slate-500">Total Net Payout</p>
              <p className="text-2xl font-bold text-slate-900">₦{currentRun.totalPayout.toLocaleString(undefined, { maximumFractionDigits: 0 })}</p>
            </div>
             <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
              <p className="text-sm text-slate-500">Total PAYE Tax</p>
              <p className="text-2xl font-bold text-blue-600">₦{currentRun.totalTax.toLocaleString(undefined, { maximumFractionDigits: 0 })}</p>
            </div>
             <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
              <p className="text-sm text-slate-500">Total Pension Remittance</p>
              <p className="text-2xl font-bold text-purple-600">₦{currentRun.totalPension.toLocaleString(undefined, { maximumFractionDigits: 0 })}</p>
            </div>
             <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
              <p className="text-sm text-slate-500">Status</p>
              <p className={`text-xl font-bold ${currentRun.status === 'Finalized' ? 'text-green-600' : 'text-amber-500'}`}>
                {currentRun.status}
              </p>
            </div>
          </div>

          {/* Payroll Table */}
          <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-left text-sm">
                <thead className="bg-slate-50 text-slate-600 font-medium border-b border-slate-200">
                  <tr>
                    <th className="px-4 py-3">Employee</th>
                    <th className="px-4 py-3">Status</th>
                    <th className="px-4 py-3">Verification</th>
                    <th className="px-4 py-3">Basic + Allowances</th>
                    <th className="px-4 py-3 w-32">Overtime (₦)</th>
                    <th className="px-4 py-3">Gross</th>
                    <th className="px-4 py-3">Deductions</th>
                    <th className="px-4 py-3 bg-slate-100 font-bold">Net Pay</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {currentRun.entries.map((entry) => {
                    const isGhostRisk = entry.employeeStatus === EmployeeStatus.RESIGNED && entry.netPay > 0;
                    const isBiometricRisk = !entry.isBiometricVerified && entry.employeeStatus === EmployeeStatus.ACTIVE;

                    return (
                      <tr key={entry.employeeId} className={`hover:bg-slate-50 ${isGhostRisk || isBiometricRisk ? 'bg-red-50' : ''}`}>
                        <td className="px-4 py-3 font-medium">
                          {entry.employeeName}
                          {isGhostRisk && (
                            <div className="flex items-center gap-1 text-xs text-red-600 font-bold mt-1">
                              <AlertCircle size={12} /> GHOST WORKER
                            </div>
                          )}
                          {isBiometricRisk && (
                             <div className="flex items-center gap-1 text-xs text-red-600 font-bold mt-1">
                              <ShieldAlert size={12} /> IDENTITY UNVERIFIED
                            </div>
                          )}
                        </td>
                        <td className="px-4 py-3 text-xs">{entry.employeeStatus}</td>
                        <td className="px-4 py-3">
                          {entry.isBiometricVerified ? (
