                          ) : (
                            <span className="text-red-500 flex items-center gap-1 text-xs font-bold"><ShieldAlert size={14}/> Missing</span>
                          )}
                        </td>
                        <td className="px-4 py-3">₦{(entry.basic + entry.housing + entry.transport).toLocaleString()}</td>

                        {/* Inputs: Editable only if Draft */}
                        <td className="px-4 py-3">
                           {currentRun.status === 'Draft' ? (
                             <input 
                              type="number" 
                              className="w-full border rounded p-1 text-right"
                              value={variableInputs[entry.employeeId]?.overtime || 0}
                              onChange={(e) => updateVariableInput(entry.employeeId, 'overtime', Number(e.target.value))}
                            />
                           ) : (
                             <span>₦{entry.overtime.toLocaleString()}</span>
                           )}
                        </td>

                        <td className="px-4 py-3 font-medium">₦{entry.grossIncome.toLocaleString()}</td>
                        <td className="px-4 py-3 text-red-600 text-xs">
                          <div>Tax: ₦{entry.taxPAYE.toLocaleString(undefined, { maximumFractionDigits: 0 })}</div>
                          <div>Pension: ₦{(entry.pensionEmployee + entry.pensionEmployer).toLocaleString(undefined, { maximumFractionDigits: 0 })}</div>
                        </td>
                        <td className="px-4 py-3 font-bold text-slate-900 bg-slate-50 border-l">
                          ₦{entry.netPay.toLocaleString(undefined, { maximumFractionDigits: 0 })}
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
             <div className="p-4 bg-slate-50 border-t border-slate-200 text-xs text-slate-500 flex justify-between items-center">
                <span>* Pension: 8% Employee + 10% Employer. Tax: PITA Bands applies.</span>
                {currentRun.status === 'Draft' && (
                  <span className="text-amber-600 font-medium">Draft Mode - Values not final. Click 'Generate Draft' after editing inputs.</span>
                )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

