import React, { useState, useEffect } from 'react';
import { Employee, EmployeeStatus, PayrollRun, PayrollEntry } from '../types';
import { calculatePayrollEntry } from '../services/payrollUtils';
import { explainPayrollBlock } from '../services/geminiService';
import { Play, Save, Download, RefreshCw, AlertCircle, ScanFace, ShieldAlert, Loader2, XCircle, Bot } from 'lucide-react';
import ReactMarkdown from 'react-markdown';

interface PayrollProcessorProps {
  employees: Employee[];
  payrollRuns: PayrollRun[];
  setPayrollRuns: React.Dispatch<React.SetStateAction<PayrollRun[]>>;
}

const PayrollProcessor: React.FC<PayrollProcessorProps> = ({ employees, payrollRuns, setPayrollRuns }) => {
  const [selectedMonth, setSelectedMonth] = useState('2023-11');
  const [currentRun, setCurrentRun] = useState<PayrollRun | null>(null);

  // Local state for variable inputs before calculation
  const [variableInputs, setVariableInputs] = useState<Record<string, { overtime: number, bonus: number, loanPaid: number }>>({});

  // Blocking State
  const [blockingExplanation, setBlockingExplanation] = useState<string | null>(null);
  const [isAnalyzingBlock, setIsAnalyzingBlock] = useState(false);

  useEffect(() => {
    // Check if run exists
    const existingRun = payrollRuns.find(r => r.month === selectedMonth);
    setCurrentRun(existingRun || null);
  }, [selectedMonth, payrollRuns]);

  const handleGenerateDraft = () => {
    const entries: PayrollEntry[] = employees.map(emp => {
      const inputs = variableInputs[emp.id] || { overtime: 0, bonus: 0, loanPaid: 0 };
      return calculatePayrollEntry(emp, inputs.overtime, inputs.bonus, inputs.loanPaid);
    });

    const totalPayout = entries.reduce((acc, curr) => acc + curr.netPay, 0);
    const totalTax = entries.reduce((acc, curr) => acc + curr.taxPAYE, 0);
    const totalPension = entries.reduce((acc, curr) => acc + curr.pensionEmployee + curr.pensionEmployer, 0);

    const newRun: PayrollRun = {
      id: crypto.randomUUID(),
      month: selectedMonth,
      status: 'Draft',
      entries,
      totalPayout,
      totalTax,
      totalPension,
      dateCreated: new Date().toISOString()
    };

    setCurrentRun(newRun);
    setBlockingExplanation(null); // Clear previous blocks
  };

  const handleFinalize = async () => {
    if (!currentRun) return;

    // --- COMPLIANCE & RISK CHECKS ---
    const issues = [];

    // 1. Ghost Worker Check
    const ghostWorkers = currentRun.entries.filter(e => e.employeeStatus === EmployeeStatus.RESIGNED && e.netPay > 0);
    if (ghostWorkers.length > 0) {
      issues.push({
        type: "Ghost Worker Detected",
        details: ghostWorkers.map(e => `${e.employeeName} is marked RESIGNED but has calculated Net Pay of ₦${e.netPay.toLocaleString()}.`)
      });
    }

    // 2. Biometric Verification Check
    const unverified = currentRun.entries.filter(e => !e.isBiometricVerified && e.employeeStatus === EmployeeStatus.ACTIVE);
    if (unverified.length > 0) {
      issues.push({
        type: "Biometric Verification Missing",
        details: unverified.map(e => `${e.employeeName} is ACTIVE but has no face biometrics enrolled.`)
      });
    }

    // If issues exist, BLOCK and EXPLAIN
    if (issues.length > 0) {
      setIsAnalyzingBlock(true);
      const explanation = await explainPayrollBlock(issues);
      setBlockingExplanation(explanation);
      setIsAnalyzingBlock(false);
      return; // STOP execution
    }
    // --------------------------------

    const finalRun = { ...currentRun, status: 'Finalized' as const };
    const otherRuns = payrollRuns.filter(r => r.month !== selectedMonth);
    setPayrollRuns([...otherRuns, finalRun]);
    setCurrentRun(finalRun);

    alert("Payroll finalized successfully!");
  };

  const updateVariableInput = (id: string, field: 'overtime' | 'bonus' | 'loanPaid', value: number) => {
    setVariableInputs(prev => ({
      ...prev,
      [id]: {
        ...prev[id] || { overtime: 0, bonus: 0, loanPaid: 0 },
        [field]: value
      }
    }));
  };

  return (
    <div className="p-6 relative">
       <div className="flex justify-between items-center mb-6">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Run Payroll</h2>
          <p className="text-slate-500">Calculate salaries, taxes, and deductions for {selectedMonth}.</p>
        </div>
        <div className="flex items-center gap-3">
            <input 
              type="month" 
              className="border p-2 rounded-lg bg-white"
              value={selectedMonth}
              onChange={(e) => setSelectedMonth(e.target.value)}
            />
            {(!currentRun || currentRun.status === 'Draft') && (
              <button 
                onClick={handleGenerateDraft}
                className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition shadow"
              >
                <RefreshCw size={18} /> {currentRun ? 'Recalculate Draft' : 'Generate Draft'}
              </button>
            )}
            {currentRun?.status === 'Draft' && (
              <button 
                onClick={handleFinalize}
                className="bg-green-600 hover:bg-green-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition shadow"
              >
                <Save size={18} /> Finalize Payroll
              </button>
            )}
            {currentRun?.status === 'Finalized' && (
              <button className="bg-slate-800 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition shadow cursor-not-allowed opacity-80">
                <Save size={18} /> Finalized
              </button>
            )}
        </div>
      </div>

      {!currentRun && (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-12 flex flex-col items-center justify-center text-center">
            <div className="bg-blue-50 p-4 rounded-full text-blue-500 mb-4">
              <Play size={32} />
            </div>
            <h3 className="text-lg font-semibold text-slate-800">Ready to Process</h3>
            <p className="text-slate-500 max-w-md mt-2">
              Select a month and click "Generate Draft" to start the payroll calculation engine. 
              The system will automatically compute PAYE, Pension, and Deductions.
            </p>
        </div>
      )}

      {currentRun && (
        <div className="space-y-6">
          {/* Summary Cards */}
          <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
            <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
              <p className="text-sm text-slate-500">Total Net Payout</p>
              <p className="text-2xl font-bold text-slate-900">₦{currentRun.totalPayout.toLocaleString(undefined, { maximumFractionDigits: 0 })}</p>
            </div>
             <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
              <p className="text-sm text-slate-500">Total PAYE Tax</p>
              <p className="text-2xl font-bold text-blue-600">₦{currentRun.totalTax.toLocaleString(undefined, { maximumFractionDigits: 0 })}</p>
            </div>
             <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
              <p className="text-sm text-slate-500">Total Pension Remittance</p>
              <p className="text-2xl font-bold text-purple-600">₦{currentRun.totalPension.toLocaleString(undefined, { maximumFractionDigits: 0 })}</p>
            </div>
             <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
              <p className="text-sm text-slate-500">Status</p>
              <p className={`text-xl font-bold ${currentRun.status === 'Finalized' ? 'text-green-600' : 'text-amber-500'}`}>
                {currentRun.status}
              </p>
            </div>
          </div>

          {/* Payroll Table */}
          <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-left text-sm">
                <thead className="bg-slate-50 text-slate-600 font-medium border-b border-slate-200">
                  <tr>
                    <th className="px-4 py-3">Employee</th>
                    <th className="px-4 py-3">Status</th>
                    <th className="px-4 py-3">Verification</th>
                    <th className="px-4 py-3">Basic + Allowances</th>
                    <th className="px-4 py-3 w-32">Overtime (₦)</th>
                    <th className="px-4 py-3">Gross</th>
                    <th className="px-4 py-3">Deductions</th>
                    <th className="px-4 py-3 bg-slate-100 font-bold">Net Pay</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {currentRun.entries.map((entry) => {
                    const isGhostRisk = entry.employeeStatus === EmployeeStatus.RESIGNED && entry.netPay > 0;
                    const isBiometricRisk = !entry.isBiometricVerified && entry.employeeStatus === EmployeeStatus.ACTIVE;

                    return (
                      <tr key={entry.employeeId} className={`hover:bg-slate-50 ${isGhostRisk || isBiometricRisk ? 'bg-red-50' : ''}`}>
                        <td className="px-4 py-3 font-medium">
                          {entry.employeeName}
                          {isGhostRisk && (
                            <div className="flex items-center gap-1 text-xs text-red-600 font-bold mt-1">
                              <AlertCircle size={12} /> GHOST WORKER
                            </div>
                          )}
                          {isBiometricRisk && (
                             <div className="flex items-center gap-1 text-xs text-red-600 font-bold mt-1">
                              <ShieldAlert size={12} /> IDENTITY UNVERIFIED
                            </div>
                          )}
                        </td>
                        <td className="px-4 py-3 text-xs">{entry.employeeStatus}</td>
                        <td className="px-4 py-3">
                          {entry.isBiometricVerified ? (
                            <span className="text-green-600 flex items-center gap-1 text-xs font-bold"><ScanFace size={14}/> Verified</span>
                          ) : (
                            <span className="text-red-500 flex items-center gap-1 text-xs font-bold"><ShieldAlert size={14}/> Missing</span>
                          )}
                        </td>
                        <td className="px-4 py-3">₦{(entry.basic + entry.housing + entry.transport).toLocaleString()}</td>

                        {/* Inputs: Editable only if Draft */}
                        <td className="px-4 py-3">
                           {currentRun.status === 'Draft' ? (
                             <input 
                              type="number" 
                              className="w-full border rounded p-1 text-right"
                              value={variableInputs[entry.employeeId]?.overtime || 0}
                              onChange={(e) => updateVariableInput(entry.employeeId, 'overtime', Number(e.target.value))}
                            />
                           ) : (
                             <span>₦{entry.overtime.toLocaleString()}</span>
                           )}
                        </td>

                        <td className="px-4 py-3 font-medium">₦{entry.grossIncome.toLocaleString()}</td>
                        <td className="px-4 py-3 text-red-600 text-xs">
                          <div>Tax: ₦{entry.taxPAYE.toLocaleString(undefined, { maximumFractionDigits: 0 })}</div>
                          <div>Pension: ₦{(entry.pensionEmployee + entry.pensionEmployer).toLocaleString(undefined, { maximumFractionDigits: 0 })}</div>
                        </td>
                        <td className="px-4 py-3 font-bold text-slate-900 bg-slate-50 border-l">
                          ₦{entry.netPay.toLocaleString(undefined, { maximumFractionDigits: 0 })}
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
             <div className="p-4 bg-slate-50 border-t border-slate-200 text-xs text-slate-500 flex justify-between items-center">
                <span>* Pension: 8% Employee + 10% Employer. Tax: PITA Bands applies.</span>
                {currentRun.status === 'Draft' && (
                  <span className="text-amber-600 font-medium">Draft Mode - Values not final. Click 'Generate Draft' after editing inputs.</span>
                )}
            </div>
          </div>
        </div>
      )}

      {/* Compliance Blocking Modal */}
      {(isAnalyzingBlock || blockingExplanation) && (
        <div className="fixed inset-0 bg-black/70 flex items-center justify-center z-50 backdrop-blur-sm">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl overflow-hidden border-2 border-red-500 animate-in fade-in zoom-in duration-300">

             {/* Header */}
             <div className="bg-red-50 p-6 border-b border-red-100 flex items-center justify-between">
                <div className="flex items-center gap-3">
                   <div className="bg-red-100 p-2 rounded-full text-red-600">
                      <ShieldAlert size={32} />
                   </div>
                   <div>
                     <h3 className="text-xl font-bold text-slate-900">Payroll Finalization Blocked</h3>
                     <p className="text-sm text-red-600 font-medium">Compliance Intervention Required</p>
                   </div>
                </div>
                <button onClick={() => setBlockingExplanation(null)} className="text-slate-400 hover:text-slate-600">
                  <XCircle size={24} />
                </button>
             </div>

             {/* Content */}
             <div className="p-6 max-h-[60vh] overflow-y-auto">
               {isAnalyzingBlock ? (
                 <div className="flex flex-col items-center justify-center py-12">
                   <Loader2 className="animate-spin text-red-500 mb-4" size={48} />
                   <h4 className="text-lg font-semibold text-slate-700">Analyzing Risk Factors...</h4>
                   <p className="text-sm text-slate-500">Consulting AI Compliance Engine</p>
                 </div>
               ) : (
                 <div className="prose prose-sm prose-red max-w-none">
                    <div className="flex items-center gap-2 mb-4 text-slate-800 font-bold bg-slate-100 p-3 rounded-lg border border-slate-200">
                      <Bot size={20} className="text-purple-600" />
                      <span>Explainable AI Report:</span>
                    </div>
                    <ReactMarkdown>{blockingExplanation || ""}</ReactMarkdown>
                 </div>
               )}
             </div>

             {/* Footer */}
             <div className="p-4 bg-slate-50 border-t flex justify-end">
               <button 
                onClick={() => setBlockingExplanation(null)}
                className="bg-slate-900 text-white px-6 py-2 rounded-lg font-medium hover:bg-slate-800 transition"
               >
                 Acknowledge & Fix
               </button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

