import { GoogleGenAI } from "@google/genai";
import { PayrollRun, EmployeeStatus } from '../types';

export const analyzePayroll = async (payrollRun: PayrollRun, previousRun?: PayrollRun | null) => {
  if (!process.env.API_KEY) {
    console.warn("API Key is missing for Gemini");
    return "API Key missing. Cannot perform AI audit.";
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Prepare a summarized version of data to save tokens and focus attention
  const summaryData = {
    month: payrollRun.month,
    totalStaff: payrollRun.entries.length,
    totalPayout: payrollRun.totalPayout,
    entries: payrollRun.entries.map(e => ({
      name: e.employeeName,
      status: e.employeeStatus,
      netPay: e.netPay,
      tax: e.taxPAYE,
      pension: e.pensionEmployee,
      loanPaid: e.loanDeduction,
      overtime: e.overtime
    }))
  };

  let comparisonContext = "";
  if (previousRun) {
     const prevSummary = {
        month: previousRun.month,
        entries: previousRun.entries.map(e => ({
            name: e.employeeName,
            netPay: e.netPay,
            overtime: e.overtime
        }))
     };
     comparisonContext = `
     COMPARISON DATA (Previous Month - ${previousRun.month}):
     ${JSON.stringify(prevSummary)}

     INSTRUCTIONS FOR ANOMALY DETECTION:
     Compare the "Current Payroll Data" with "comparisonComparison Data".
     1. **Salary Spikes**: Identify employees whose Net Pay increased significantly (e.g., > 15%) compared to the previous month. State the percentage increase.
     2. **Overtime Anomalies**: Identify employees with sudden overtime spikes compared to previous month (e.g. they had 0 before and now have a lot).
     3. **Duplicate Payments**: Check for duplicate names/entries in the current run.
     `;
  }

  const prompt = `
    You are an expert HR and Payroll Auditor for a Nigerian manufacturing company.
    Analyze the following payroll run data for compliance and anomalies.

    ${comparisonContext}

    Current Payroll Data (${payrollRun.month}):
    ${JSON.stringify(summaryData)}

    Specific things to check (Standard Rules):
    1. **Ghost Workers**: Are there any employees with status '${EmployeeStatus.RESIGNED}' or '${EmployeeStatus.SUSPENDED}' who are receiving a Net Pay > 0? This is critical.
    2. **Unusual Overtime**: Flag any employee earning overtime that is more than 50% of their basic salary (if overtime > 0).
    3. **Tax/Pension Compliance**: Briefly confirm if tax and pension seem to be calculated (non-zero) for active employees.

    Output Format:
    Provide a professional Markdown report.
    - Start with an "Executive Summary".
    - Use a section "🚨 Anomaly Detected" for salary jumps, overtime spikes, or duplicates.
    - Use a section "⚠️ Compliance Risks" for ghost workers or tax issues.
    - If comparing, explicitly state: "Employee X salary increased by Y% compared to last month."
    - If everything looks good, state that the payroll appears clean.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 0 } // Speed over deep thought for this
      }
    });

    return response.text;
  } catch (error) {
    console.error("Gemini Audit Error:", error);
    return "An error occurred while communicating with the AI Auditor.";
  }
};

export const explainPayrollBlock = async (issues: any[]) => {
  if (!process.env.API_KEY) return "API Key missing.";
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    You are the Compliance Officer AI for a Nigerian company using PayPulse.
    The payroll finalization has been BLOCKED due to the following high-risk irregularities found in the draft:

    ${JSON.stringify(issues, null, 2)}

    Explain clearly and authoritatively why the payroll was blocked (Explainable AI).
    For each issue:
    1. **Explain the specific error** (e.g., "Ghost Worker detected" or "Pension Mismatch").
    2. **Explain the risk** (e.g., "Paying a resigned employee constitutes financial loss and fraud risk").
    3. **Recommend the immediate action** (e.g., "Remove Tola from payroll or update status").

    Keep it concise but stern. This is a safety intervention.
  `;

  try {
     const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt
    });
    return response.text;
  } catch (e) {
    return "Unable to generate AI explanation at this time.";
  }
};

export const askPayrollAssistant = async (question: string, contextData: any) => {
   if (!process.env.API_KEY) {
    return "API Key missing.";
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    You are an expert Payroll Assistant for a Nigerian company.
    Context Data (Current Payroll/Employee Stats): ${JSON.stringify(contextData)}

    User Question: ${question}

    Answer clearly and concisely. If it involves tax law, refer to Nigerian PITA.
  `;

  try {
    const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt
    });
    return response.text;
  } catch (error) {
      return "I couldn't process your request at this time.";
  }
}

import React, { useState } from 'react';
import { PayrollRun } from '../types';
import { analyzePayroll, askPayrollAssistant } from '../services/geminiService';
import { Bot, CheckCircle, AlertTriangle, Loader2, Send, History } from 'lucide-react';
import ReactMarkdown from 'react-markdown';

interface GeminiAuditProps {
  payrollRuns: PayrollRun[];
}

const GeminiAudit: React.FC<GeminiAuditProps> = ({ payrollRuns }) => {
  const [auditResult, setAuditResult] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [selectedRunId, setSelectedRunId] = useState<string>(payrollRuns.length > 0 ? payrollRuns[payrollRuns.length - 1].id : '');

  // Chat state
  const [chatInput, setChatInput] = useState('');
  const [chatResponse, setChatResponse] = useState<string | null>(null);
  const [chatLoading, setChatLoading] = useState(false);

  const handleAudit = async () => {
    const run = payrollRuns.find(r => r.id === selectedRunId);
    if (!run) return;

    // Find Previous Run for Anomaly Detection (Comparison)
    const sortedRuns = [...payrollRuns].sort((a, b) => a.month.localeCompare(b.month));
    const currentIndex = sortedRuns.findIndex(r => r.id === run.id);
    const previousRun = currentIndex > 0 ? sortedRuns[currentIndex - 1] : null;

    setLoading(true);
    setAuditResult(null);

    // Pass both current and previous run to the AI
    const result = await analyzePayroll(run, previousRun);

    setAuditResult(result);
    setLoading(false);
  };

  const handleChat = async () => {
    if(!chatInput.trim()) return;
    setChatLoading(true);
    const context = payrollRuns.find(r => r.id === selectedRunId) || "No payroll selected";
    const result = await askPayrollAssistant(chatInput, context);
    setChatResponse(result);
    setChatLoading(false);
  };

  return (
    <div className="p-6 h-screen overflow-y-auto">
      <div className="mb-6">
        <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
          <Bot className="text-purple-600" /> AI Compliance & Anomaly Auditor
        </h2>
        <p className="text-slate-500">Leverage Gemini to detect ghost workers, salary jumps, and anomalies.</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Audit Section */}
        <div className="space-y-6">
           <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
            <h3 className="font-semibold text-lg mb-4">Run Audit</h3>
            <div className="bg-blue-50 p-4 rounded-lg text-sm text-blue-800 mb-4 flex gap-2">
               <History size={18} className="shrink-0 mt-0.5" />
               <div>
                  <strong>Anomaly Detection Active:</strong> The AI will compare the selected month against the previous month to flag unusual salary hikes or overtime spikes.
               </div>
            </div>

            <div className="flex gap-4 mb-4">
              <select 
                className="flex-1 border p-2 rounded-lg"
                value={selectedRunId}
                onChange={(e) => setSelectedRunId(e.target.value)}
              >
                {payrollRuns.length === 0 && <option>No payroll runs available</option>}
                {payrollRuns.map(run => (
                  <option key={run.id} value={run.id}>{run.month} ({run.status})</option>
                ))}
              </select>
              <button 
                onClick={handleAudit}
                disabled={loading || payrollRuns.length === 0}
                className="bg-purple-600 text-white px-4 py-2 rounded-lg hover:bg-purple-700 disabled:opacity-50 flex items-center gap-2 transition"
              >
                {loading ? <Loader2 className="animate-spin" size={18} /> : <CheckCircle size={18} />}
                Start Audit
              </button>
            </div>

            {auditResult && (
              <div className="mt-4 p-4 bg-slate-50 rounded-lg border border-slate-200 prose prose-sm max-w-none">
                <div className="flex items-center gap-2 mb-2 text-purple-700 font-semibold border-b border-slate-200 pb-2">
                  <Bot size={16} /> Analysis Report
                </div>
                <ReactMarkdown>{auditResult}</ReactMarkdown>
              </div>
            )}
            {!auditResult && !loading && (
              <div className="text-center py-10 text-slate-400">
                <AlertTriangle className="mx-auto mb-2 opacity-50" size={32} />
                <p>Select a payroll run and click audit to scan for irregularities.</p>
              </div>
            )}
          </div>
        </div>

        {/* Chat Section */}
        <div className="flex flex-col h-full min-h-[500px] bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
          <div className="p-4 border-b bg-slate-50">
             <h3 className="font-semibold text-lg">Payroll Assistant</h3>
             <p className="text-xs text-slate-500">Ask about tax laws, specific calculations, or summary stats.</p>
          </div>

          <div className="flex-1 p-4 overflow-y-auto space-y-4">
            <div className="flex gap-3">
               <div className="w-8 h-8 rounded-full bg-purple-100 flex items-center justify-center text-purple-600">
                 <Bot size={16} />
               </div>
               <div className="bg-slate-100 p-3 rounded-lg rounded-tl-none max-w-[80%] text-sm">
                 Hello Mr. Adebayo! I can help you explain tax calculations, verify pension rates, or summarize the selected payroll run. What do you need?
               </div>
            </div>

            {chatResponse && (
               <div className="flex gap-3">
               <div className="w-8 h-8 rounded-full bg-purple-100 flex items-center justify-center text-purple-600">
                 <Bot size={16} />
               </div>
               <div className="bg-purple-50 p-3 rounded-lg rounded-tl-none max-w-[80%] text-sm text-slate-800">
                 <ReactMarkdown>{chatResponse}</ReactMarkdown>
               </div>
            </div>
            )}
             {chatLoading && (
               <div className="flex gap-3">
                  <div className="w-8 h-8 rounded-full bg-purple-100 flex items-center justify-center text-purple-600">
                   <Bot size={16} />
                 </div>
                 <div className="text-slate-400 text-sm italic">Thinking...</div>
               </div>
            )}
          </div>

          <div className="p-4 border-t">
            <div className="flex gap-2">
              <input 
                type="text" 
                className="flex-1 border rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-purple-500"
                placeholder="e.g., Why is Tola's tax higher this month?"
                value={chatInput}
                onChange={(e) => setChatInput(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleChat()}
              />
              <button 
                onClick={handleChat}
                disabled={chatLoading}
                className="bg-purple-600 text-white p-2 rounded-lg hover:bg-purple-700"
              >
                <Send size={20} />
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

