import React, { useState, useRef } from 'react';
import { Employee, EmployeeStatus } from '../types';
import { Plus, Search, Edit2, UserX, UserCheck, ScanFace, Camera, Upload, CheckCircle, X } from 'lucide-react';

interface EmployeeManagerProps {
  employees: Employee[];
  setEmployees: React.Dispatch<React.SetStateAction<Employee[]>>;
}

const EmployeeManager: React.FC<EmployeeManagerProps> = ({ employees, setEmployees }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [showModal, setShowModal] = useState(false);
  const [showBiometricModal, setShowBiometricModal] = useState(false);
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);

  // Biometric State
  const [biometricStep, setBiometricStep] = useState<'start' | 'scanning' | 'processing' | 'success'>('start');
  const videoRef = useRef<HTMLVideoElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);

  // Initial State for form
  const initialFormState: Employee = {
    id: '',
    firstName: '',
    lastName: '',
    email: '',
    phoneNumber: '',
    designation: '',
    department: '',
    basicSalary: 0,
    housingAllowance: 0,
    transportAllowance: 0,
    pfa: 'Stanbic IBTC Pension Managers',
    rsaNumber: '',
    status: EmployeeStatus.ACTIVE,
    joinDate: new Date().toISOString().split('T')[0],
    cooperativeLoanBalance: 0,
    faceVerified: false
  };

  const [formData, setFormData] = useState<Employee>(initialFormState);

  const handleSave = () => {
    if (editingEmployee) {
      setEmployees(prev => prev.map(emp => emp.id === editingEmployee.id ? { ...formData, id: emp.id } : emp));
    } else {
      const newEmployee = { ...formData, id: crypto.randomUUID() };
      setEmployees(prev => [...prev, newEmployee]);
    }
    setShowModal(false);
    setEditingEmployee(null);
    setFormData(initialFormState);
  };

  const handleEdit = (employee: Employee) => {
    setEditingEmployee(employee);
    setFormData(employee);
    setShowModal(true);
  };

  const handleEnrollFace = (employee: Employee) => {
    setEditingEmployee(employee);
    setBiometricStep('start');
    setShowBiometricModal(true);
  };

  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({ video: true });
      setStream(mediaStream);
      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream;
      }
      setBiometricStep('scanning');
    } catch (err) {
      alert("Camera access denied or unavailable. Please use upload.");
    }
  };

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
  };

  const captureAndVerify = () => {
    setBiometricStep('processing');
    stopCamera();
    // Simulate API delay
    setTimeout(() => {
      if (editingEmployee) {
         setEmployees(prev => prev.map(emp => emp.id === editingEmployee.id ? { ...emp, faceVerified: true } : emp));
      }
      setBiometricStep('success');
    }, 2000);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setBiometricStep('processing');
      // Simulate upload and processing
      setTimeout(() => {
        if (editingEmployee) {
           setEmployees(prev => prev.map(emp => emp.id === editingEmployee.id ? { ...emp, faceVerified: true } : emp));
        }
        setBiometricStep('success');
      }, 1500);
    }
  };

  const closeBiometricModal = () => {
    stopCamera();
    setShowBiometricModal(false);
    setEditingEmployee(null);
  };

  const toggleStatus = (id: string, currentStatus: EmployeeStatus) => {
    const newStatus = currentStatus === EmployeeStatus.ACTIVE ? EmployeeStatus.RESIGNED : EmployeeStatus.ACTIVE;
    setEmployees(prev => prev.map(emp => emp.id === id ? { ...emp, status: newStatus } : emp));
  };

  const filteredEmployees = employees.filter(emp => 
    emp.firstName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.lastName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.department.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="p-6">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Employee Management</h2>
          <p className="text-slate-500">Manage your workforce, statuses, and biometric data.</p>
        </div>
        <button 
          onClick={() => { setEditingEmployee(null); setFormData(initialFormState); setShowModal(true); }}
          className="bg-green-600 hover:bg-green-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition"
        >
          <Plus size={18} /> Add Employee
        </button>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-4 border-b border-slate-200 flex gap-4">
          <div className="relative flex-1 max-w-md">
            <Search className="absolute left-3 top-2.5 text-slate-400" size={20} />
            <input 
              type="text" 
              placeholder="Search by name or department..." 
              className="w-full pl-10 pr-4 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-green-500"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
            <thead className="bg-slate-50 text-slate-600 font-medium border-b border-slate-200">
              <tr>
                <th className="px-6 py-4">Name</th>
                <th className="px-6 py-4">Department</th>
                <th className="px-6 py-4">Status</th>
                <th className="px-6 py-4">Biometrics</th>
                <th className="px-6 py-4">Loan Balance</th>
                <th className="px-6 py-4 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredEmployees.map((emp) => (
                <tr key={emp.id} className="hover:bg-slate-50 transition">
                  <td className="px-6 py-4">
                    <div className="font-medium text-slate-900">{emp.firstName} {emp.lastName}</div>
                    <div className="text-slate-500 text-xs">{emp.email}</div>
                  </td>
                  <td className="px-6 py-4 text-slate-600">{emp.department}</td>
                  <td className="px-6 py-4">
                    <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${
                      emp.status === EmployeeStatus.ACTIVE ? 'bg-green-100 text-green-800' :
                      emp.status === EmployeeStatus.RESIGNED ? 'bg-red-100 text-red-800' :
                      'bg-yellow-100 text-yellow-800'
                    }`}>
                      {emp.status}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                     {emp.faceVerified ? (
                       <div className="flex items-center gap-1 text-green-600 bg-green-50 w-fit px-2 py-1 rounded text-xs font-medium border border-green-200">
                         <ScanFace size={14} /> Verified
                       </div>
                     ) : (
                       <div className="flex items-center gap-1 text-slate-500 bg-slate-100 w-fit px-2 py-1 rounded text-xs font-medium border border-slate-200">
                         <ScanFace size={14} /> Not Enrolled
                       </div>
                     )}
                  </td>
                  <td className="px-6 py-4 text-slate-600">
                     ₦{emp.cooperativeLoanBalance.toLocaleString()}
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex items-center justify-end gap-2">
                       <button 
                        onClick={() => handleEnrollFace(emp)}
                        className={`p-1.5 rounded transition ${emp.faceVerified ? 'text-green-600 bg-green-50 hover:bg-green-100' : 'text-blue-600 bg-blue-50 hover:bg-blue-100'}`}
                        title="Biometric Enrollment"
                      >
                        <ScanFace size={16} />
                      </button>
                      <button 
                        onClick={() => handleEdit(emp)}
                        className="p-1.5 text-slate-500 hover:text-blue-600 hover:bg-blue-50 rounded"
                      >
                        <Edit2 size={16} />
                      </button>
                      <button 
                        onClick={() => toggleStatus(emp.id, emp.status)}
                        className={`p-1.5 rounded ${
                          emp.status === EmployeeStatus.ACTIVE 
                          ? 'text-slate-500 hover:text-red-600 hover:bg-red-50' 
                          : 'text-slate-500 hover:text-green-600 hover:bg-green-50'
                        }`}
                        title={emp.status === EmployeeStatus.ACTIVE ? "Mark Resigned" : "Activate"}
                      >
                        {emp.status === EmployeeStatus.ACTIVE ? <UserX size={16} /> : <UserCheck size={16} />}
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* New Employee Modal */}
      {showModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
          <div className="bg-white rounded-xl shadow-xl p-6 w-full max-w-2xl max-h-[90vh] overflow-y-auto">
            <h3 className="text-xl font-bold mb-4">{editingEmployee ? 'Edit Employee' : 'New Employee'}</h3>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">First Name</label>
                <input 
                  type="text" 
                  className="w-full border p-2 rounded" 
                  value={formData.firstName}
                  onChange={e => setFormData({...formData, firstName: e.target.value})}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">Last Name</label>
                <input 
                  type="text" 
                  className="w-full border p-2 rounded" 
                  value={formData.lastName}
                  onChange={e => setFormData({...formData, lastName: e.target.value})}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">Email</label>
                <input 
                  type="email" 
                  className="w-full border p-2 rounded" 
                  value={formData.email}
                  onChange={e => setFormData({...formData, email: e.target.value})}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">Phone Number (WhatsApp)</label>
                <input 
                  type="text" 
                  className="w-full border p-2 rounded" 
                  value={formData.phoneNumber}
                  onChange={e => setFormData({...formData, phoneNumber: e.target.value})}
                  placeholder="+234..."
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">Department</label>
                <input 
                  type="text" 
                  className="w-full border p-2 rounded" 
                  value={formData.department}
                  onChange={e => setFormData({...formData, department: e.target.value})}
                />
              </div>

              <div className="col-span-2 mt-2 pt-2 border-t border-slate-100">
                <h4 className="font-semibold text-sm text-slate-900 mb-2">Compensation (Monthly)</h4>
              </div>

              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">Basic Salary (₦)</label>
                <input 
                  type="number" 
                  className="w-full border p-2 rounded" 
                  value={formData.basicSalary}
                  onChange={e => setFormData({...formData, basicSalary: Number(e.target.value)})}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">Housing Allowance (₦)</label>
                <input 
                  type="number" 
                  className="w-full border p-2 rounded" 
                  value={formData.housingAllowance}
                  onChange={e => setFormData({...formData, housingAllowance: Number(e.target.value)})}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">Transport Allowance (₦)</label>
                <input 
                  type="number" 
                  className="w-full border p-2 rounded" 
                  value={formData.transportAllowance}
                  onChange={e => setFormData({...formData, transportAllowance: Number(e.target.value)})}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">Cooperative Loan Bal (₦)</label>
                <input 
                  type="number" 
                  className="w-full border p-2 rounded" 
                  value={formData.cooperativeLoanBalance}
                  onChange={e => setFormData({...formData, cooperativeLoanBalance: Number(e.target.value)})}
                />
              </div>

               <div className="col-span-2 mt-2 pt-2 border-t border-slate-100">
                <h4 className="font-semibold text-sm text-slate-900 mb-2">Compliance</h4>
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">PFA Name</label>
                <select 
                  className="w-full border p-2 rounded"
                  value={formData.pfa}
                  onChange={e => setFormData({...formData, pfa: e.target.value})}
                >
                  <option>Stanbic IBTC Pension Managers</option>
                  <option>ARM Pension Managers</option>
                  <option>Leadway Pensure</option>
                  <option>Fidelity Pension</option>
                  <option>Premium Pension</option>
                </select>
              </div>
               <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">RSA Number</label>
                <input 
                  type="text" 
                  className="w-full border p-2 rounded" 
                  value={formData.rsaNumber}
                  onChange={e => setFormData({...formData, rsaNumber: e.target.value})}
                />
              </div>
            </div>

            <div className="mt-6 flex justify-end gap-3">
              <button 
                onClick={() => setShowModal(false)}
                className="px-4 py-2 text-slate-600 hover:bg-slate-100 rounded-lg"
              >
                Cancel
              </button>
              <button 
                onClick={handleSave}
                className="px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 shadow"
              >
                Save Employee
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Biometric Enrollment Modal */}
      {showBiometricModal && editingEmployee && (
         <div className="fixed inset-0 bg-black/80 flex items-center justify-center z-[60]">
            <div className="bg-white rounded-xl shadow-2xl overflow-hidden w-full max-w-md">
               <div className="p-6 text-center">
                 <div className="w-16 h-16 bg-blue-50 rounded-full flex items-center justify-center mx-auto mb-4 text-blue-600">
                   <ScanFace size={32} />
                 </div>
                 <h3 className="text-xl font-bold text-slate-900">Enroll Face Biometrics</h3>
                 <p className="text-slate-500 text-sm mt-1">
                   {biometricStep === 'success' 
                     ? `Verified ${editingEmployee.firstName}'s Identity`
                     : `Verify identity for ${editingEmployee.firstName} ${editingEmployee.lastName}`}
                 </p>
               </div>

               <div className="px-6 pb-6">
                 {biometricStep === 'start' && (
                   <div className="space-y-3">
                      <button 
                        onClick={startCamera}
                        className="w-full py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-medium flex items-center justify-center gap-2 transition"
                      >
                        <Camera size={20} /> Use Camera
                      </button>
                      <div className="relative">
                        <input 
                          type="file" 
                          accept="image/*" 
                          className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                          onChange={handleFileUpload}
                        />
                         <button 
                          className="w-full py-3 bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-lg font-medium flex items-center justify-center gap-2 transition"
                        >
                          <Upload size={20} /> Upload Photo
                        </button>
                      </div>
                   </div>
                 )}

                 {biometricStep === 'scanning' && (
                   <div className="relative bg-black rounded-lg overflow-hidden aspect-square mb-4">
                     <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover"></video>
                     <div className="absolute inset-0 border-2 border-blue-500/50 rounded-lg"></div>
                     <div className="absolute inset-0 flex items-center justify-center">
                       <div className="w-48 h-48 border-2 border-dashed border-white/50 rounded-full"></div>
                     </div>
                     <button 
                        onClick={captureAndVerify}
                        className="absolute bottom-4 left-1/2 -translate-x-1/2 bg-white/20 backdrop-blur text-white px-6 py-2 rounded-full font-bold hover:bg-white/30 transition border border-white/50"
                      >
                        Capture & Verify
                      </button>
                   </div>
                 )}

                 {biometricStep === 'processing' && (
                   <div className="py-12 flex flex-col items-center">
                      <div className="w-12 h-12 border-4 border-blue-200 border-t-blue-600 rounded-full animate-spin mb-4"></div>
                      <p className="text-slate-600 font-medium">Processing biometrics...</p>
                      <p className="text-xs text-slate-400 mt-1">Creating secure hash</p>
                   </div>
                 )}

                 {biometricStep === 'success' && (
                   <div className="py-8 flex flex-col items-center">
                      <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center text-green-600 mb-4 animate-bounce">
                        <CheckCircle size={32} />
                      </div>
                      <h4 className="text-lg font-bold text-slate-800">Enrollment Successful</h4>
                      <p className="text-sm text-slate-500 text-center mt-2">
                        Employee biometrics have been securely linked to their profile.
                      </p>
                      <button 
                        onClick={closeBiometricModal}
                        className="mt-6 w-full py-2 bg-slate-900 text-white rounded-lg hover:bg-slate-800"
                      >
                        Close
                      </button>
                   </div>
                 )}
               </div>

               {biometricStep === 'start' && (
                 <button onClick={closeBiometricModal} className="absolute top-4 right-4 text-slate-400 hover:text-slate-600">
                   <X size={20} />
                 </button>
               )}
            </div>
         </div>
      )}
    </div>
  );
};

