                )}
            </div>
          </div>
        </div>
      )}

      {/* Compliance Blocking Modal */}
      {(isAnalyzingBlock || blockingExplanation) && (
        <div className="fixed inset-0 bg-black/70 flex items-center justify-center z-50 backdrop-blur-sm">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl overflow-hidden border-2 border-red-500 animate-in fade-in zoom-in duration-300">

             {/* Header */}
             <div className="bg-red-50 p-6 border-b border-red-100 flex items-center justify-between">
