                   </div>
                   <div>
                     <h3 className="text-xl font-bold text-slate-900">Payroll Finalization Blocked</h3>
                     <p className="text-sm text-red-600 font-medium">Compliance Intervention Required</p>
                   </div>
                </div>
                <button onClick={() => setBlockingExplanation(null)} className="text-slate-400 hover:text-slate-600">
                  <XCircle size={24} />
                </button>
             </div>

             {/* Content */}
             <div className="p-6 max-h-[60vh] overflow-y-auto">
               {isAnalyzingBlock ? (
                 <div className="flex flex-col items-center justify-center py-12">
                   <Loader2 className="animate-spin text-red-500 mb-4" size={48} />
                   <h4 className="text-lg font-semibold text-slate-700">Analyzing Risk Factors...</h4>
                   <p className="text-sm text-slate-500">Consulting AI Compliance Engine</p>
                 </div>
               ) : (
                 <div className="prose prose-sm prose-red max-w-none">
