                      <Bot size={20} className="text-purple-600" />
                      <span>Explainable AI Report:</span>
                    </div>
                    <ReactMarkdown>{blockingExplanation || ""}</ReactMarkdown>
                 </div>
               )}
             </div>

             {/* Footer */}
             <div className="p-4 bg-slate-50 border-t flex justify-end">
               <button 
                onClick={() => setBlockingExplanation(null)}
                className="bg-slate-900 text-white px-6 py-2 rounded-lg font-medium hover:bg-slate-800 transition"
               >
                 Acknowledge & Fix
               </button>
             </div>
          </div>
        </div>
      )}

      {/* WhatsApp Broadcast Modal */}
      {showWhatsAppModal && (
        <div className="fixed inset-0 bg-black/70 flex items-center justify-center z-50 backdrop-blur-sm">
           <div className="bg-white rounded-xl shadow-2xl w-full max-w-md overflow-hidden">
             <div className="bg-[#25D366] p-6 text-white flex items-center gap-3">
                <MessageCircle size={32} />
                <div>
                   <h3 className="text-xl font-bold">WhatsApp Bot</h3>
                   <p className="text-white/80 text-sm">Distributing Payslips & Alerts</p>
                </div>
             </div>

             <div className="p-8">
                {sendingProgress < 100 ? (
                    <div className="text-center">
                        <div className="mb-4 relative h-3 bg-slate-100 rounded-full overflow-hidden">
                           <div className="absolute top-0 left-0 h-full bg-[#25D366] transition-all duration-300" style={{ width: `${sendingProgress}%`}}></div>
                        </div>
                        <h4 className="text-lg font-bold text-slate-800 mb-1">Sending Alerts...</h4>
                        <p className="text-slate-500 text-sm">Notifying {sentCount} of {currentRun?.entries.length} employees</p>

                        <div className="mt-6 bg-slate-50 p-4 rounded-lg border border-slate-100 text-left">
                            <p className="text-xs text-slate-400 mb-2 font-mono">DEBUG: WHATSAPP_API_STREAM</p>
                            <p className="text-xs text-slate-600 font-mono line-clamp-3">
                                {'>'} Initializing secure session... <br/>
                                {'>'} Template: PAYSLIP_ALERT_V2 <br/>
                                {'>'} Dispatching to {currentRun?.entries[Math.min(sentCount, (currentRun?.entries.length || 1) - 1)].employeeName}...
                            </p>
                        </div>
                    </div>
                ) : (
                    <div className="text-center">
                        <div className="w-16 h-16 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-4 animate-bounce">
                           <CheckCircle2 size={32} />
                        </div>
                        <h4 className="text-xl font-bold text-slate-800">Broadcast Complete</h4>
                        <p className="text-slate-500 mt-2 mb-6">
                           Successfully sent {currentRun?.entries.length} payslips and payment alerts via WhatsApp.
                        </p>
                        <button 
                          onClick={() => setShowWhatsAppModal(false)}
                          className="bg-slate-900 text-white w-full py-3 rounded-lg font-bold hover:bg-slate-800"
                        >
                           Close
                        </button>
                    </div>
                )}
             </div>
           </div>
        </div>
      )}
    </div>
  );
};

