  const [showModal, setShowModal] = useState(false);
  const [showBiometricModal, setShowBiometricModal] = useState(false);
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);

  // Offboarding State
  const [showOffboardModal, setShowOffboardModal] = useState(false);
  const [offboardDate, setOffboardDate] = useState(new Date().toISOString().split('T')[0]);
  const [offboardReason, setOffboardReason] = useState('Resignation');

  // Biometric State
  const [biometricStep, setBiometricStep] = useState<'start' | 'scanning' | 'processing' | 'success'>('start');
  const videoRef = useRef<HTMLVideoElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);

  // Initial State for form
  const initialFormState: Employee = {
    id: '',
    firstName: '',
    lastName: '',
    email: '',
    phoneNumber: '',
    designation: '',
    department: '',
    basicSalary: 0,
    housingAllowance: 0,
    transportAllowance: 0,
    pfa: 'Stanbic IBTC Pension Managers',
    rsaNumber: '',
    status: EmployeeStatus.ACTIVE,
    joinDate: new Date().toISOString().split('T')[0],
    cooperativeLoanBalance: 0,
    faceVerified: false
  };

  const [formData, setFormData] = useState<Employee>(initialFormState);

  const handleSave = () => {
    if (editingEmployee) {
      setEmployees(prev => prev.map(emp => emp.id === editingEmployee.id ? { ...formData, id: emp.id } : emp));
    } else {
      const newEmployee = { ...formData, id: crypto.randomUUID() };
      setEmployees(prev => [...prev, newEmployee]);
    }
    setShowModal(false);
    setEditingEmployee(null);
    setFormData(initialFormState);
  };

  const handleEdit = (employee: Employee) => {
    setEditingEmployee(employee);
    setFormData(employee);
    setShowModal(true);
  };

  const handleEnrollFace = (employee: Employee) => {
    setEditingEmployee(employee);
    setBiometricStep('start');
    setShowBiometricModal(true);
  };

  const initiateOffboard = (employee: Employee) => {
    setEditingEmployee(employee);
    setOffboardDate(new Date().toISOString().split('T')[0]);
    setShowOffboardModal(true);
  };

  const confirmOffboard = () => {
    if (editingEmployee) {
        setEmployees(prev => prev.map(emp => emp.id === editingEmployee.id ? { 
            ...emp, 
            status: EmployeeStatus.RESIGNED,
            exitDate: offboardDate 
        } : emp));
        setShowOffboardModal(false);
        setEditingEmployee(null);
    }
  };

  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({ video: true });
      setStream(mediaStream);
      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream;
      }
      setBiometricStep('scanning');
    } catch (err) {
      alert("Camera access denied or unavailable. Please use upload.");
    }
  };

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
  };

  const captureAndVerify = () => {
    setBiometricStep('processing');
    stopCamera();
    // Simulate API delay
    setTimeout(() => {
      if (editingEmployee) {
         setEmployees(prev => prev.map(emp => emp.id === editingEmployee.id ? { ...emp, faceVerified: true } : emp));
      }
      setBiometricStep('success');
    }, 2000);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setBiometricStep('processing');
      // Simulate upload and processing
      setTimeout(() => {
        if (editingEmployee) {
           setEmployees(prev => prev.map(emp => emp.id === editingEmployee.id ? { ...emp, faceVerified: true } : emp));
        }
        setBiometricStep('success');
      }, 1500);
    }
  };

  const closeBiometricModal = () => {
    stopCamera();
    setShowBiometricModal(false);
    setEditingEmployee(null);
  };

  const reactivateEmployee = (id: string) => {
    if (confirm("Are you sure you want to reactivate this employee?")) {
        setEmployees(prev => prev.map(emp => emp.id === id ? { ...emp, status: EmployeeStatus.ACTIVE, exitDate: undefined } : emp));
    }
  };

  const filteredEmployees = employees.filter(emp => 
    emp.firstName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.lastName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.department.toLowerCase().includes(searchTerm.toLowerCase())
  );

  // Final Pay Calculation Helper
  const getFinalPayEstimate = () => {
      if (!editingEmployee) return { days: 0, gross: 0, prorated: 0, loan: 0, final: 0 };

      const exitDay = new Date(offboardDate).getDate();
      const monthlyGross = editingEmployee.basicSalary + editingEmployee.housingAllowance + editingEmployee.transportAllowance;
      const dailyRate = monthlyGross / 30; // Using 30 days as standard basis
      const proratedSalary = dailyRate * exitDay;
      const loan = editingEmployee.cooperativeLoanBalance;
      const final = Math.max(0, proratedSalary - loan);

      return {
          days: exitDay,
          gross: monthlyGross,
          prorated: proratedSalary,
          loan: loan,
          final: final
      };
  };

  const finalPay = getFinalPayEstimate();

  return (
    <div className="p-6">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Employee Management</h2>
          <p className="text-slate-500">Manage your workforce, statuses, and biometric data.</p>
        </div>
        <button 
          onClick={() => { setEditingEmployee(null); setFormData(initialFormState); setShowModal(true); }}
          className="bg-green-600 hover:bg-green-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition"
        >
          <Plus size={18} /> Add Employee
        </button>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-4 border-b border-slate-200 flex gap-4">
          <div className="relative flex-1 max-w-md">
            <Search className="absolute left-3 top-2.5 text-slate-400" size={20} />
            <input 
              type="text" 
              placeholder="Search by name or department..." 
              className="w-full pl-10 pr-4 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-green-500"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
            <thead className="bg-slate-50 text-slate-600 font-medium border-b border-slate-200">
              <tr>
                <th className="px-6 py-4">Name</th>
                <th className="px-6 py-4">Department</th>
                <th className="px-6 py-4">Status</th>
                <th className="px-6 py-4">Biometrics</th>
                <th className="px-6 py-4">Loan Balance</th>
                <th className="px-6 py-4 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredEmployees.map((emp) => (
                <tr key={emp.id} className="hover:bg-slate-50 transition">
                  <td className="px-6 py-4">
                    <div className="font-medium text-slate-900">{emp.firstName} {emp.lastName}</div>
                    <div className="text-slate-500 text-xs">{emp.email}</div>
                  </td>
                  <td className="px-6 py-4 text-slate-600">{emp.department}</td>
                  <td className="px-6 py-4">
                    <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${
                      emp.status === EmployeeStatus.ACTIVE ? 'bg-green-100 text-green-800' :
                      emp.status === EmployeeStatus.RESIGNED ? 'bg-red-100 text-red-800' :
                      'bg-yellow-100 text-yellow-800'
                    }`}>
                      {emp.status}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                     {emp.faceVerified ? (
                       <div className="flex items-center gap-1 text-green-600 bg-green-50 w-fit px-2 py-1 rounded text-xs font-medium border border-green-200">
                         <ScanFace size={14} /> Verified
                       </div>
                     ) : (
                       <div className="flex items-center gap-1 text-slate-500 bg-slate-100 w-fit px-2 py-1 rounded text-xs font-medium border border-slate-200">
                         <ScanFace size={14} /> Not Enrolled
                       </div>
                     )}
                  </td>
                  <td className="px-6 py-4 text-slate-600">
                     ₦{emp.cooperativeLoanBalance.toLocaleString()}
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex items-center justify-end gap-2">
                       <button 
                        onClick={() => handleEnrollFace(emp)}
                        className={`p-1.5 rounded transition ${emp.faceVerified ? 'text-green-600 bg-green-50 hover:bg-green-100' : 'text-blue-600 bg-blue-50 hover:bg-blue-100'}`}
                        title="Biometric Enrollment"
                      >
                        <ScanFace size={16} />
                      </button>
                      <button 
                        onClick={() => handleEdit(emp)}
                        className="p-1.5 text-slate-500 hover:text-blue-600 hover:bg-blue-50 rounded"
                        title="Edit Details"
                      >
                        <Edit2 size={16} />
                      </button>

                      {emp.status === EmployeeStatus.ACTIVE ? (
                        <button 
                          onClick={() => initiateOffboard(emp)}
                          className="p-1.5 rounded text-slate-500 hover:text-red-600 hover:bg-red-50"
                          title="Offboard Employee (Exit)"
                        >
                          <UserMinus size={16} />
                        </button>
                      ) : (
                        <button 
                          onClick={() => reactivateEmployee(emp.id)}
                          className="p-1.5 rounded text-slate-500 hover:text-green-600 hover:bg-green-50"
                          title="Reactivate Employee"
                        >
                          <UserCheck size={16} />
                        </button>
                      )}
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* New Employee Modal */}
      {showModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
          <div className="bg-white rounded-xl shadow-xl p-6 w-full max-w-2xl max-h-[90vh] overflow-y-auto">
            <h3 className="text-xl font-bold mb-4">{editingEmployee ? 'Edit Employee' : 'New Employee'}</h3>
            {/* ... Form Content Same as Before ... */}
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">First Name</label>
                <input 
                  type="text" 
                  className="w-full border p-2 rounded" 
                  value={formData.firstName}
                  onChange={e => setFormData({...formData, firstName: e.target.value})}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">Last Name</label>
                <input 
                  type="text" 
                  className="w-full border p-2 rounded" 
                  value={formData.lastName}
                  onChange={e => setFormData({...formData, lastName: e.target.value})}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">Email</label>
                <input 
                  type="email" 
                  className="w-full border p-2 rounded" 
                  value={formData.email}
                  onChange={e => setFormData({...formData, email: e.target.value})}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">Phone Number (WhatsApp)</label>
                <input 
                  type="text" 
                  className="w-full border p-2 rounded" 
                  value={formData.phoneNumber}
                  onChange={e => setFormData({...formData, phoneNumber: e.target.value})}
                  placeholder="+234..."
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">Department</label>
                <input 
                  type="text" 
                  className="w-full border p-2 rounded" 
                  value={formData.department}
                  onChange={e => setFormData({...formData, department: e.target.value})}
                />
              </div>

              <div className="col-span-2 mt-2 pt-2 border-t border-slate-100">
                <h4 className="font-semibold text-sm text-slate-900 mb-2">Compensation (Monthly)</h4>
              </div>

              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">Basic Salary (₦)</label>
                <input 
                  type="number" 
                  className="w-full border p-2 rounded" 
                  value={formData.basicSalary}
                  onChange={e => setFormData({...formData, basicSalary: Number(e.target.value)})}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">Housing Allowance (₦)</label>
                <input 
                  type="number" 
                  className="w-full border p-2 rounded" 
                  value={formData.housingAllowance}
                  onChange={e => setFormData({...formData, housingAllowance: Number(e.target.value)})}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">Transport Allowance (₦)</label>
                <input 
                  type="number" 
                  className="w-full border p-2 rounded" 
                  value={formData.transportAllowance}
                  onChange={e => setFormData({...formData, transportAllowance: Number(e.target.value)})}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">Cooperative Loan Bal (₦)</label>
                <input 
                  type="number" 
                  className="w-full border p-2 rounded" 
                  value={formData.cooperativeLoanBalance}
                  onChange={e => setFormData({...formData, cooperativeLoanBalance: Number(e.target.value)})}
                />
              </div>

               <div className="col-span-2 mt-2 pt-2 border-t border-slate-100">
                <h4 className="font-semibold text-sm text-slate-900 mb-2">Compliance</h4>
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">PFA Name</label>
                <select 
                  className="w-full border p-2 rounded"
                  value={formData.pfa}
                  onChange={e => setFormData({...formData, pfa: e.target.value})}
                >
                  <option>Stanbic IBTC Pension Managers</option>
                  <option>ARM Pension Managers</option>
                  <option>Leadway Pensure</option>
                  <option>Fidelity Pension</option>
                  <option>Premium Pension</option>
                </select>
              </div>
               <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">RSA Number</label>
                <input 
                  type="text" 
                  className="w-full border p-2 rounded" 
                  value={formData.rsaNumber}
                  onChange={e => setFormData({...formData, rsaNumber: e.target.value})}
                />
              </div>
            </div>

            <div className="mt-6 flex justify-end gap-3">
              <button 
                onClick={() => setShowModal(false)}
                className="px-4 py-2 text-slate-600 hover:bg-slate-100 rounded-lg"
              >
                Cancel
              </button>
              <button 
                onClick={handleSave}
                className="px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 shadow"
              >
                Save Employee
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Offboarding Modal */}
      {showOffboardModal && editingEmployee && (
        <div className="fixed inset-0 bg-black/60 flex items-center justify-center z-[55]">
            <div className="bg-white rounded-xl shadow-2xl p-6 w-full max-w-lg">
                <div className="flex items-center gap-3 mb-6 pb-4 border-b">
                    <div className="bg-red-100 p-3 rounded-full text-red-600">
                        <UserMinus size={24} />
                    </div>
                    <div>
                        <h3 className="text-xl font-bold text-slate-900">Offboard Employee</h3>
                        <p className="text-sm text-slate-500">Initiate exit and calculate final settlement.</p>
                    </div>
                </div>

                <div className="space-y-4">
                    <div className="bg-slate-50 p-4 rounded-lg border border-slate-200">
                         <div className="flex justify-between mb-2">
                             <span className="text-sm text-slate-500">Employee</span>
                             <span className="font-bold text-slate-900">{editingEmployee.firstName} {editingEmployee.lastName}</span>
                         </div>
                         <div className="flex justify-between">
                             <span className="text-sm text-slate-500">Department</span>
                             <span className="font-medium text-slate-700">{editingEmployee.department}</span>
                         </div>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-1">
                            <label className="text-xs font-bold text-slate-700 uppercase">Exit Date</label>
                            <input 
                              type="date" 
                              className="w-full border p-2 rounded-lg"
                              value={offboardDate}
                              onChange={(e) => setOffboardDate(e.target.value)}
                            />
                        </div>
                         <div className="space-y-1">
                            <label className="text-xs font-bold text-slate-700 uppercase">Reason</label>
                            <select 
                                className="w-full border p-2 rounded-lg"
                                value={offboardReason}
                                onChange={(e) => setOffboardReason(e.target.value)}
                            >
                                <option>Resignation</option>
                                <option>Termination</option>
                                <option>Retirement</option>
                                <option>Absconded</option>
                            </select>
                        </div>
                    </div>

                    <div className="bg-blue-50 rounded-xl p-4 border border-blue-100 mt-4">
                        <h4 className="flex items-center gap-2 font-bold text-blue-800 mb-3">
                            <Calculator size={16} /> Final Settlement Estimate
                        </h4>
                        <div className="space-y-2 text-sm">
                            <div className="flex justify-between text-blue-900/70">
                                <span>Monthly Gross</span>
                                <span>₦{finalPay.gross.toLocaleString()}</span>
                            </div>
                            <div className="flex justify-between text-blue-900/70">
                                <span>Days Worked in Month ({finalPay.days} days)</span>
                                <span>(Prorated)</span>
                            </div>
                            <div className="flex justify-between font-medium text-blue-900 pt-1 border-t border-blue-200">
                                <span>Prorated Salary</span>
                                <span>₦{finalPay.prorated.toLocaleString(undefined, {maximumFractionDigits: 0})}</span>
                            </div>
                             <div className="flex justify-between text-red-600">
                                <span>Less: Outstanding Loan</span>
                                <span>-₦{finalPay.loan.toLocaleString()}</span>
                            </div>
                            <div className="flex justify-between font-bold text-lg text-slate-900 pt-2 border-t border-blue-200 mt-2">
                                <span>Net Final Pay</span>
                                <span>₦{finalPay.final.toLocaleString(undefined, {maximumFractionDigits: 0})}</span>
                            </div>
                        </div>
                    </div>

                    <div className="flex items-start gap-2 text-xs text-amber-700 bg-amber-50 p-3 rounded-lg border border-amber-100">
                        <div className="mt-0.5"><Calendar size={14} /></div>
                        <p>
                            Confirming this will set status to <strong>Resigned</strong> and stop automatic salary generation in future payroll runs.
                        </p>
                    </div>
                </div>

                <div className="mt-6 flex gap-3">
                    <button 
                      onClick={() => setShowOffboardModal(false)}
                      className="flex-1 py-3 text-slate-600 font-medium hover:bg-slate-50 rounded-lg"
                    >
                        Cancel
                    </button>
                    <button 
                      onClick={confirmOffboard}
                      className="flex-1 py-3 bg-red-600 text-white font-bold rounded-lg hover:bg-red-700 shadow-lg shadow-red-200 transition"
                    >
                        Confirm Exit
                    </button>
                </div>
            </div>
        </div>
      )}

      {/* Biometric Enrollment Modal */}
      {showBiometricModal && editingEmployee && (
         <div className="fixed inset-0 bg-black/80 flex items-center justify-center z-[60]">
            <div className="bg-white rounded-xl shadow-2xl overflow-hidden w-full max-w-md">
               <div className="p-6 text-center">
                 <div className="w-16 h-16 bg-blue-50 rounded-full flex items-center justify-center mx-auto mb-4 text-blue-600">
                   <ScanFace size={32} />
                 </div>
                 <h3 className="text-xl font-bold text-slate-900">Enroll Face Biometrics</h3>
                 <p className="text-slate-500 text-sm mt-1">
                   {biometricStep === 'success' 
                     ? `Verified ${editingEmployee.firstName}'s Identity`
                     : `Verify identity for ${editingEmployee.firstName} ${editingEmployee.lastName}`}
                 </p>
               </div>

               <div className="px-6 pb-6">
                 {biometricStep === 'start' && (
                   <div className="space-y-3">
                      <button 
                        onClick={startCamera}
                        className="w-full py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-medium flex items-center justify-center gap-2 transition"
                      >
                        <Camera size={20} /> Use Camera
                      </button>
                      <div className="relative">
                        <input 
                          type="file" 
                          accept="image/*" 
                          className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                          onChange={handleFileUpload}
                        />
                         <button 
                          className="w-full py-3 bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-lg font-medium flex items-center justify-center gap-2 transition"
                        >
                          <Upload size={20} /> Upload Photo
                        </button>
                      </div>
                   </div>
                 )}

                 {biometricStep === 'scanning' && (
                   <div className="relative bg-black rounded-lg overflow-hidden aspect-square mb-4">
                     <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover"></video>
                     <div className="absolute inset-0 border-2 border-blue-500/50 rounded-lg"></div>
                     <div className="absolute inset-0 flex items-center justify-center">
                       <div className="w-48 h-48 border-2 border-dashed border-white/50 rounded-full"></div>
                     </div>
                     <button 
                        onClick={captureAndVerify}
                        className="absolute bottom-4 left-1/2 -translate-x-1/2 bg-white/20 backdrop-blur text-white px-6 py-2 rounded-full font-bold hover:bg-white/30 transition border border-white/50"
                      >
                        Capture & Verify
                      </button>
                   </div>
                 )}

                 {biometricStep === 'processing' && (
                   <div className="py-12 flex flex-col items-center">
                      <div className="w-12 h-12 border-4 border-blue-200 border-t-blue-600 rounded-full animate-spin mb-4"></div>
                      <p className="text-slate-600 font-medium">Processing biometrics...</p>
                      <p className="text-xs text-slate-400 mt-1">Creating secure hash</p>
                   </div>
                 )}

                 {biometricStep === 'success' && (
                   <div className="py-8 flex flex-col items-center">
                      <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center text-green-600 mb-4 animate-bounce">
                        <CheckCircle size={32} />
                      </div>
                      <h4 className="text-lg font-bold text-slate-800">Enrollment Successful</h4>
                      <p className="text-sm text-slate-500 text-center mt-2">
                        Employee biometrics have been securely linked to their profile.
                      </p>
                      <button 
                        onClick={closeBiometricModal}
                        className="mt-6 w-full py-2 bg-slate-900 text-white rounded-lg hover:bg-slate-800"
                      >
                        Close
                      </button>
                   </div>
                 )}
               </div>

               {biometricStep === 'start' && (
                 <button onClick={closeBiometricModal} className="absolute top-4 right-4 text-slate-400 hover:text-slate-600">
                   <X size={20} />
                 </button>
               )}
            </div>
         </div>
      )}
    </div>
  );
};

export default EmployeeManager;

import React, { useState, useEffect } from 'react';
import { Employee, EmployeeStatus, PayrollRun, PayrollEntry } from '../types';
import { calculatePayrollEntry } from '../services/payrollUtils';
import { explainPayrollBlock } from '../services/geminiService';
import { Play, Save, Download, RefreshCw, AlertCircle, ScanFace, ShieldAlert, Loader2, XCircle, Bot, CheckCircle2, FileCheck, MessageCircle, Send } from 'lucide-react';
import ReactMarkdown from 'react-markdown';

interface PayrollProcessorProps {
  employees: Employee[];
  payrollRuns: PayrollRun[];
  setPayrollRuns: React.Dispatch<React.SetStateAction<PayrollRun[]>>;
}

const PayrollProcessor: React.FC<PayrollProcessorProps> = ({ employees, payrollRuns, setPayrollRuns }) => {
  const [selectedMonth, setSelectedMonth] = useState('2023-12');
  const [currentRun, setCurrentRun] = useState<PayrollRun | null>(null);

  // Local state for variable inputs before calculation
  const [variableInputs, setVariableInputs] = useState<Record<string, { overtime: number, bonus: number, loanPaid: number }>>({});

  // Blocking State
  const [blockingExplanation, setBlockingExplanation] = useState<string | null>(null);
  const [isAnalyzingBlock, setIsAnalyzingBlock] = useState(false);

  // Validation State
  const [validationStatus, setValidationStatus] = useState<'valid' | 'issues' | null>(null);

  // WhatsApp Alert Bot State
  const [showWhatsAppModal, setShowWhatsAppModal] = useState(false);
  const [sendingProgress, setSendingProgress] = useState(0);
  const [sentCount, setSentCount] = useState(0);

  useEffect(() => {
    // Check if run exists
    const existingRun = payrollRuns.find(r => r.month === selectedMonth);
    setCurrentRun(existingRun || null);
    if (existingRun) {
        setValidationStatus('valid'); // Assume finalized runs are valid
    } else {
        setValidationStatus(null);
    }
  }, [selectedMonth, payrollRuns]);

  const calculateEntries = () => {
      return employees.map(emp => {
      // Feature: Stop salary for resigned employees automatically
      // If status is RESIGNED, we return a zeroed entry to ensure they are not paid
      // unless specifically manually overridden later (which would be caught by anomaly detection)
      if (emp.status === EmployeeStatus.RESIGNED) {
          return {
              employeeId: emp.id,
              employeeName: `${emp.firstName} ${emp.lastName}`,
              employeeStatus: emp.status,
              basic: 0, housing: 0, transport: 0, grossIncome: 0, overtime: 0, bonuses: 0,
              pensionEmployee: 0, pensionEmployer: 0, taxPAYE: 0, loanDeduction: 0, otherDeductions: 0,
              totalDeductions: 0, netPay: 0, isBiometricVerified: emp.faceVerified
          };
      }

      const inputs = variableInputs[emp.id] || { overtime: 0, bonus: 0, loanPaid: 0 };
      return calculatePayrollEntry(emp, inputs.overtime, inputs.bonus, inputs.loanPaid);
    });
  }

  const validateRun = (entries: PayrollEntry[]) => {
    const ghostWorkers = entries.filter(e => e.employeeStatus === EmployeeStatus.RESIGNED && e.netPay > 0);
    const unverified = entries.filter(e => !e.isBiometricVerified && e.employeeStatus === EmployeeStatus.ACTIVE);

    return {
        ghostWorkers,
        unverified,
        hasIssues: ghostWorkers.length > 0 || unverified.length > 0
    };
  };

  const handleRunPayroll = () => {
    const entries = calculateEntries();

    const totalPayout = entries.reduce((acc, curr) => acc + curr.netPay, 0);
    const totalTax = entries.reduce((acc, curr) => acc + curr.taxPAYE, 0);
    const totalPension = entries.reduce((acc, curr) => acc + curr.pensionEmployee + curr.pensionEmployer, 0);

    const newRun: PayrollRun = {
      id: crypto.randomUUID(),
      month: selectedMonth,
      status: 'Draft',
      entries,
      totalPayout,
      totalTax,
      totalPension,
      dateCreated: new Date().toISOString()
    };

    setCurrentRun(newRun);
    setBlockingExplanation(null); 

    // Auto-Validate
    const { hasIssues } = validateRun(entries);
    setValidationStatus(hasIssues ? 'issues' : 'valid');
  };

  const handleFinalize = async () => {
    if (!currentRun) return;

    const { ghostWorkers, unverified } = validateRun(currentRun.entries);
    const issues = [];

    if (ghostWorkers.length > 0) {
      issues.push({
        type: "Ghost Worker Detected",
        details: ghostWorkers.map(e => `${e.employeeName} is marked RESIGNED but has calculated Net Pay of ₦${e.netPay.toLocaleString()}.`)
      });
    }

    if (unverified.length > 0) {
      issues.push({
        type: "Biometric Verification Missing",
        details: unverified.map(e => `${e.employeeName} is ACTIVE but has no face biometrics enrolled.`)
      });
    }

    // If issues exist, BLOCK and EXPLAIN
    if (issues.length > 0) {
      setIsAnalyzingBlock(true);
      const explanation = await explainPayrollBlock(issues);
      setBlockingExplanation(explanation);
      setIsAnalyzingBlock(false);
      return; // STOP execution
    }

    const finalRun = { ...currentRun, status: 'Finalized' as const };
    const otherRuns = payrollRuns.filter(r => r.month !== selectedMonth);
    setPayrollRuns([...otherRuns, finalRun]);
    setCurrentRun(finalRun);

    alert("Payroll finalized successfully!");
  };

  const startWhatsAppBroadcast = () => {
    if (!currentRun) return;
    setShowWhatsAppModal(true);
    setSendingProgress(0);
    setSentCount(0);

    // Simulate sending delay
    const total = currentRun.entries.length;
    let current = 0;

    const interval = setInterval(() => {
        current += 1;
        setSentCount(current);
        setSendingProgress((current / total) * 100);

        if (current >= total) {
            clearInterval(interval);
        }
    }, 600); // 600ms per employee
  };

  const updateVariableInput = (id: string, field: 'overtime' | 'bonus' | 'loanPaid', value: number) => {
    setVariableInputs(prev => ({
      ...prev,
      [id]: {
        ...prev[id] || { overtime: 0, bonus: 0, loanPaid: 0 },
        [field]: value
      }
    }));
  };

  return (
    <div className="p-6 relative pb-24">
       <div className="flex justify-between items-center mb-6">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Run Payroll</h2>
          <p className="text-slate-500">Calculate salaries, taxes, and deductions for {selectedMonth}.</p>
        </div>
        <div className="flex items-center gap-3">
            <input 
              type="month" 
              className="border p-2 rounded-lg bg-white shadow-sm"
              value={selectedMonth}
              onChange={(e) => setSelectedMonth(e.target.value)}
            />
            {currentRun && currentRun.status === 'Draft' && (
               <button 
                onClick={handleRunPayroll}
                className="text-blue-600 hover:bg-blue-50 px-4 py-2 rounded-lg flex items-center gap-2 transition font-medium"
              >
                <RefreshCw size={18} /> Re-Run Calculation
              </button>
            )}
        </div>
      </div>

      {!currentRun && (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-16 flex flex-col items-center justify-center text-center max-w-2xl mx-auto mt-10">
            <div className="bg-blue-100 p-6 rounded-full text-blue-600 mb-6 shadow-inner">
              <Play size={48} fill="currentColor" />
            </div>
            <h3 className="text-2xl font-bold text-slate-800">Ready to Process Payroll</h3>
            <p className="text-slate-500 mt-2 mb-8 max-w-md">
              Click below to automatically calculate deductions, validate compliance, and check for ghost workers for <strong>{selectedMonth}</strong>.
            </p>
            <button 
              onClick={handleRunPayroll}
              className="bg-blue-600 hover:bg-blue-700 text-white text-lg font-bold px-8 py-4 rounded-xl shadow-lg hover:shadow-blue-500/30 transition transform hover:-translate-y-1 flex items-center gap-3"
            >
               Run Payroll for {selectedMonth}
            </button>
        </div>
      )}

      {currentRun && (
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">

          {/* Finalized Action Banner */}
          {currentRun.status === 'Finalized' && (
             <div className="bg-green-50 p-4 rounded-xl border border-green-200 flex items-center justify-between">
                <div className="flex items-center gap-3">
                    <div className="bg-green-100 p-2 rounded-full text-green-700">
                        <CheckCircle2 size={24} />
                    </div>
                    <div>
                        <h4 className="font-bold text-lg text-green-900">Payroll is Finalized</h4>
                        <p className="text-sm text-green-700">All data is locked and reports are ready for distribution.</p>
                    </div>
                </div>
                <div className="flex gap-2">
                    <button 
                      onClick={startWhatsAppBroadcast}
                      className="bg-green-600 text-white px-5 py-2.5 rounded-lg font-bold shadow-sm hover:bg-green-700 transition flex items-center gap-2"
                    >
                        <MessageCircle size={18} /> Send WhatsApp Alerts
                    </button>
                </div>
             </div>
          )}

          {/* Validation Status Banner (Only for Draft) */}
          {currentRun.status === 'Draft' && (
             <div className={`p-4 rounded-xl border flex items-start gap-4 ${
                 validationStatus === 'issues' ? 'bg-red-50 border-red-200 text-red-900' : 'bg-slate-50 border-slate-200 text-slate-700'
             }`}>
                <div className={`p-2 rounded-full ${validationStatus === 'issues' ? 'bg-red-100 text-red-600' : 'bg-green-100 text-green-600'}`}>
                    {validationStatus === 'issues' ? <AlertCircle size={24} /> : <CheckCircle2 size={24} />}
                </div>
                <div className="flex-1">
                    <h4 className="font-bold text-lg">
                        {validationStatus === 'issues' ? 'Compliance Issues Detected' : 'Data Validation Passed'}
                    </h4>
                    <p className="text-sm opacity-90 mt-1">
                        {validationStatus === 'issues' 
                           ? 'The system has flagged potential ghost workers or unverified employees. Please review the highlighted entries below before finalizing.'
                           : 'All calculations are complete. No ghost workers or compliance risks detected.'
                        }
                    </p>
                </div>
                {validationStatus === 'valid' && (
                    <button 
                        onClick={handleFinalize}
                        className="bg-green-600 text-white px-6 py-2 rounded-lg font-bold shadow-sm hover:bg-green-700 transition flex items-center gap-2"
                    >
                        <Save size={18} /> Finalize Run
                    </button>
                )}
                {validationStatus === 'issues' && (
                    <button 
                        onClick={handleFinalize}
                        className="bg-red-600 text-white px-6 py-2 rounded-lg font-bold shadow-sm hover:bg-red-700 transition flex items-center gap-2"
                    >
                        Review & Resolve
                    </button>
                )}
             </div>
          )}

          {/* Summary Cards */}
          <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
            <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
              <p className="text-sm text-slate-500">Total Net Payout</p>
              <p className="text-2xl font-bold text-slate-900">₦{currentRun.totalPayout.toLocaleString(undefined, { maximumFractionDigits: 0 })}</p>
            </div>
             <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
              <p className="text-sm text-slate-500">Total PAYE Tax</p>
              <p className="text-2xl font-bold text-blue-600">₦{currentRun.totalTax.toLocaleString(undefined, { maximumFractionDigits: 0 })}</p>
            </div>
             <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
              <p className="text-sm text-slate-500">Total Pension Remittance</p>
              <p className="text-2xl font-bold text-purple-600">₦{currentRun.totalPension.toLocaleString(undefined, { maximumFractionDigits: 0 })}</p>
            </div>
             <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex flex-col justify-center">
                <div className="flex items-center gap-2 text-sm text-slate-500 mb-1">
                    <FileCheck size={16} /> Reports Ready
                </div>
                <div className="flex gap-2">
                    <span className="text-xs bg-slate-100 text-slate-600 px-2 py-1 rounded">PAYE</span>
                    <span className="text-xs bg-slate-100 text-slate-600 px-2 py-1 rounded">Pension</span>
                    <span className="text-xs bg-slate-100 text-slate-600 px-2 py-1 rounded">Bank</span>
                </div>
            </div>
          </div>

          {/* Payroll Table */}
          <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-left text-sm">
                <thead className="bg-slate-50 text-slate-600 font-medium border-b border-slate-200">
                  <tr>
                    <th className="px-4 py-3">Employee</th>
                    <th className="px-4 py-3">Status</th>
                    <th className="px-4 py-3">Verification</th>
                    <th className="px-4 py-3">Basic + Allowances</th>
                    <th className="px-4 py-3 w-32">Overtime (₦)</th>
                    <th className="px-4 py-3">Gross</th>
                    <th className="px-4 py-3">Deductions</th>
                    <th className="px-4 py-3 bg-slate-100 font-bold">Net Pay</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {currentRun.entries.map((entry) => {
                    const isGhostRisk = entry.employeeStatus === EmployeeStatus.RESIGNED && entry.netPay > 0;
                    const isBiometricRisk = !entry.isBiometricVerified && entry.employeeStatus === EmployeeStatus.ACTIVE;
                    const hasError = isGhostRisk || isBiometricRisk;

                    return (
                      <tr key={entry.employeeId} className={`hover:bg-slate-50 ${hasError ? 'bg-red-50/70' : ''}`}>
                        <td className="px-4 py-3 font-medium">
                          {entry.employeeName}
                          {isGhostRisk && (
                            <div className="flex items-center gap-1 text-xs text-red-600 font-bold mt-1 animate-pulse">
                              <AlertCircle size={12} /> GHOST WORKER DETECTED
                            </div>
                          )}
                          {isBiometricRisk && (
                             <div className="flex items-center gap-1 text-xs text-red-600 font-bold mt-1">
                              <ShieldAlert size={12} /> IDENTITY UNVERIFIED
                            </div>
                          )}
                        </td>
                        <td className="px-4 py-3 text-xs">{entry.employeeStatus}</td>
                        <td className="px-4 py-3">
                          {entry.isBiometricVerified ? (
                            <span className="text-green-600 flex items-center gap-1 text-xs font-bold"><ScanFace size={14}/> Verified</span>
                          ) : (
                            <span className="text-red-500 flex items-center gap-1 text-xs font-bold"><ShieldAlert size={14}/> Missing</span>
                          )}
                        </td>
                        <td className="px-4 py-3">₦{(entry.basic + entry.housing + entry.transport).toLocaleString()}</td>

                        {/* Inputs: Editable only if Draft */}
                        <td className="px-4 py-3">
                           {currentRun.status === 'Draft' ? (
                             <input 
                              type="number" 
                              className="w-full border rounded p-1 text-right focus:ring-2 focus:ring-blue-500 outline-none"
                              value={variableInputs[entry.employeeId]?.overtime || 0}
                              onChange={(e) => updateVariableInput(entry.employeeId, 'overtime', Number(e.target.value))}
                              disabled={entry.employeeStatus === EmployeeStatus.RESIGNED}
                            />
                           ) : (
                             <span>₦{entry.overtime.toLocaleString()}</span>
                           )}
                        </td>

                        <td className="px-4 py-3 font-medium">₦{entry.grossIncome.toLocaleString()}</td>
                        <td className="px-4 py-3 text-red-600 text-xs">
                          <div>Tax: ₦{entry.taxPAYE.toLocaleString(undefined, { maximumFractionDigits: 0 })}</div>
                          <div>Pension: ₦{(entry.pensionEmployee + entry.pensionEmployer).toLocaleString(undefined, { maximumFractionDigits: 0 })}</div>
                        </td>
                        <td className="px-4 py-3 font-bold text-slate-900 bg-slate-50 border-l">
                          ₦{entry.netPay.toLocaleString(undefined, { maximumFractionDigits: 0 })}
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
             <div className="p-4 bg-slate-50 border-t border-slate-200 text-xs text-slate-500 flex justify-between items-center">
                <span>* Pension: 8% Employee + 10% Employer. Tax: PITA Bands applies.</span>
                {currentRun.status === 'Draft' && (
                  <span className="text-amber-600 font-medium">Draft Mode - Values not final. Edit Overtime/Bonuses above if needed.</span>
                )}
            </div>
          </div>
        </div>
      )}

      {/* Compliance Blocking Modal */}
      {(isAnalyzingBlock || blockingExplanation) && (
        <div className="fixed inset-0 bg-black/70 flex items-center justify-center z-50 backdrop-blur-sm">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl overflow-hidden border-2 border-red-500 animate-in fade-in zoom-in duration-300">

             {/* Header */}
             <div className="bg-red-50 p-6 border-b border-red-100 flex items-center justify-between">
                <div className="flex items-center gap-3">
                   <div className="bg-red-100 p-2 rounded-full text-red-600">
                      <ShieldAlert size={32} />
                   </div>
                   <div>
                     <h3 className="text-xl font-bold text-slate-900">Payroll Finalization Blocked</h3>
                     <p className="text-sm text-red-600 font-medium">Compliance Intervention Required</p>
                   </div>
                </div>
                <button onClick={() => setBlockingExplanation(null)} className="text-slate-400 hover:text-slate-600">
                  <XCircle size={24} />
                </button>
             </div>

             {/* Content */}
             <div className="p-6 max-h-[60vh] overflow-y-auto">
               {isAnalyzingBlock ? (
                 <div className="flex flex-col items-center justify-center py-12">
                   <Loader2 className="animate-spin text-red-500 mb-4" size={48} />
                   <h4 className="text-lg font-semibold text-slate-700">Analyzing Risk Factors...</h4>
                   <p className="text-sm text-slate-500">Consulting AI Compliance Engine</p>
                 </div>
               ) : (
                 <div className="prose prose-sm prose-red max-w-none">
                    <div className="flex items-center gap-2 mb-4 text-slate-800 font-bold bg-slate-100 p-3 rounded-lg border border-slate-200">
                      <Bot size={20} className="text-purple-600" />
                      <span>Explainable AI Report:</span>
                    </div>
                    <ReactMarkdown>{blockingExplanation || ""}</ReactMarkdown>
                 </div>
               )}
             </div>

             {/* Footer */}
             <div className="p-4 bg-slate-50 border-t flex justify-end">
               <button 
                onClick={() => setBlockingExplanation(null)}
                className="bg-slate-900 text-white px-6 py-2 rounded-lg font-medium hover:bg-slate-800 transition"
               >
                 Acknowledge & Fix
               </button>
             </div>
          </div>
        </div>
      )}

      {/* WhatsApp Broadcast Modal */}
      {showWhatsAppModal && (
        <div className="fixed inset-0 bg-black/70 flex items-center justify-center z-50 backdrop-blur-sm">
           <div className="bg-white rounded-xl shadow-2xl w-full max-w-md overflow-hidden">
             <div className="bg-[#25D366] p-6 text-white flex items-center gap-3">
                <MessageCircle size={32} />
                <div>
                   <h3 className="text-xl font-bold">WhatsApp Bot</h3>
                   <p className="text-white/80 text-sm">Distributing Payslips & Alerts</p>
                </div>
             </div>

             <div className="p-8">
                {sendingProgress < 100 ? (
                    <div className="text-center">
                        <div className="mb-4 relative h-3 bg-slate-100 rounded-full overflow-hidden">
                           <div className="absolute top-0 left-0 h-full bg-[#25D366] transition-all duration-300" style={{ width: `${sendingProgress}%`}}></div>
                        </div>
                        <h4 className="text-lg font-bold text-slate-800 mb-1">Sending Alerts...</h4>
                        <p className="text-slate-500 text-sm">Notifying {sentCount} of {currentRun?.entries.length} employees</p>

                        <div className="mt-6 bg-slate-50 p-4 rounded-lg border border-slate-100 text-left">
                            <p className="text-xs text-slate-400 mb-2 font-mono">DEBUG: WHATSAPP_API_STREAM</p>
                            <p className="text-xs text-slate-600 font-mono line-clamp-3">
                                {'>'} Initializing secure session... <br/>
                                {'>'} Template: PAYSLIP_ALERT_V2 <br/>
                                {'>'} Dispatching to {currentRun?.entries[Math.min(sentCount, (currentRun?.entries.length || 1) - 1)].employeeName}...
                            </p>
                        </div>
                    </div>
                ) : (
                    <div className="text-center">
                        <div className="w-16 h-16 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-4 animate-bounce">
                           <CheckCircle2 size={32} />
                        </div>
                        <h4 className="text-xl font-bold text-slate-800">Broadcast Complete</h4>
                        <p className="text-slate-500 mt-2 mb-6">
                           Successfully sent {currentRun?.entries.length} payslips and payment alerts via WhatsApp.
                        </p>
                        <button 
                          onClick={() => setShowWhatsAppModal(false)}
                          className="bg-slate-900 text-white w-full py-3 rounded-lg font-bold hover:bg-slate-800"
                        >
                           Close
                        </button>
                    </div>
                )}
             </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default PayrollProcessor;

export enum EmployeeStatus {
  ACTIVE = 'Active',
  RESIGNED = 'Resigned',
  SUSPENDED = 'Suspended',
  ON_LEAVE = 'On Leave'
}

export interface Employee {
  id: string;
  firstName: string;
  lastName: string;
  email: string;
  phoneNumber: string; // NEW: For WhatsApp Alerts
