  rate: number;
}

export interface ComplianceTask {
  id: string;
  title: string;
  authority: string; // e.g., LIRS, PENCOM
  dueDate: string;
  daysRemaining: number;
  status: 'Pending' | 'Filed' | 'Overdue';
  severity: 'Critical' | 'Warning' | 'Good';
}

