import React, { useState } from 'react';
import { AuditLogEntry } from '../types';
import { Search, Filter, Shield, Clock, User, FileText, Download } from 'lucide-react';

interface AuditLogViewerProps {
  logs: AuditLogEntry[];
}

const AuditLogViewer: React.FC<AuditLogViewerProps> = ({ logs }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [categoryFilter, setCategoryFilter] = useState('All');

  const filteredLogs = logs.filter(log => {
    const matchesSearch = 
      log.action.toLowerCase().includes(searchTerm.toLowerCase()) || 
      log.details.toLowerCase().includes(searchTerm.toLowerCase()) ||
      log.user.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesCategory = categoryFilter === 'All' || log.category === categoryFilter;
    return matchesSearch && matchesCategory;
  });

  return (
    <div className="p-6 h-screen overflow-y-auto">
      <div className="mb-6">
        <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
          <Shield className="text-slate-600" /> Audit Logs & Change History
        </h2>
        <p className="text-slate-500">Track all system activities, salary changes, and payroll events for compliance.</p>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        {/* Toolbar */}
        <div className="p-4 border-b border-slate-200 flex flex-col md:flex-row gap-4 justify-between items-center bg-slate-50">
           <div className="flex gap-4 w-full md:w-auto">
             <div className="relative flex-1 md:w-80">
                <Search className="absolute left-3 top-2.5 text-slate-400" size={18} />
                <input 
                  type="text" 
                  placeholder="Search logs..." 
                  className="w-full pl-10 pr-4 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm"
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                />
             </div>
             <select 
                className="border border-slate-300 rounded-lg px-3 py-2 text-sm bg-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                value={categoryFilter}
                onChange={(e) => setCategoryFilter(e.target.value)}
             >
                <option value="All">All Categories</option>
                <option value="Payroll">Payroll</option>
                <option value="Employee">Employee Data</option>
                <option value="Compliance">Compliance</option>
                <option value="System">System</option>
             </select>
           </div>

           <button className="flex items-center gap-2 text-slate-600 hover:text-blue-600 text-sm font-medium px-3 py-2 rounded-lg hover:bg-white transition">
              <Download size={16} /> Export Log
           </button>
        </div>

        {/* Table */}
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
             <thead className="bg-slate-100 text-slate-600 font-semibold border-b border-slate-200">
                <tr>
                   <th className="px-6 py-4 w-48">Timestamp</th>
                   <th className="px-6 py-4 w-40">User</th>
                   <th className="px-6 py-4 w-32">Category</th>
                   <th className="px-6 py-4 w-48">Action</th>
                   <th className="px-6 py-4">Details</th>
                </tr>
             </thead>
             <tbody className="divide-y divide-slate-100">
                {filteredLogs.length === 0 ? (
                  <tr>
                    <td colSpan={5} className="px-6 py-12 text-center text-slate-400">
                       No audit records found matching your filters.
                    </td>
                  </tr>
                ) : (
                  filteredLogs.map(log => (
                    <tr key={log.id} className="hover:bg-slate-50 transition">
                       <td className="px-6 py-4 text-slate-500 font-mono text-xs">
                          <div className="flex items-center gap-2">
                             <Clock size={14} />
                             {new Date(log.timestamp).toLocaleString()}
                          </div>
                       </td>
                       <td className="px-6 py-4">
                          <div className="flex items-center gap-2 text-slate-700 font-medium">
                             <User size={14} className="text-slate-400" />
                             {log.user}
                          </div>
                       </td>
                       <td className="px-6 py-4">
                          <span className={`inline-flex px-2.5 py-1 rounded-full text-xs font-medium border ${
                             log.category === 'Payroll' ? 'bg-green-50 text-green-700 border-green-100' :
                             log.category === 'Employee' ? 'bg-blue-50 text-blue-700 border-blue-100' :
                             log.category === 'Compliance' ? 'bg-red-50 text-red-700 border-red-100' :
                             'bg-slate-100 text-slate-700 border-slate-200'
                          }`}>
                             {log.category}
                          </span>
                       </td>
                       <td className="px-6 py-4 font-medium text-slate-800">
                          {log.action}
                       </td>
                       <td className="px-6 py-4 text-slate-600 max-w-md truncate" title={log.details}>
                          {log.details}
                       </td>
                    </tr>
                  ))
                )}
             </tbody>
          </table>
        </div>

        <div className="p-4 border-t border-slate-200 bg-slate-50 text-xs text-slate-500 flex justify-between items-center">
           <span>Showing {filteredLogs.length} of {logs.length} records</span>
           <span>Audit logs are immutable and stored securely.</span>
        </div>
      </div>
    </div>
  );
};

