import Forecasting from './components/Forecasting';
import { Employee, EmployeeStatus, PayrollRun, AuditLogEntry, PayrollEntry } from './types';
import { calculatePayrollEntry } from './services/payrollUtils';

// Helper to generate random employees
const generateDummyData = () => {
  const departments = ['Production', 'Sales', 'HR', 'Finance', 'Logistics', 'Engineering', 'Quality Control'];
  const designations = ['Operator', 'Supervisor', 'Manager', 'Assistant', 'Analyst', 'Driver', 'Technician'];
  const pfas = ['Stanbic IBTC Pension Managers', 'ARM Pension Managers', 'Leadway Pensure', 'Fidelity Pension', 'Premium Pension'];
  const firstNames = ['Olu', 'Ade', 'Chi', 'Emeka', 'Fatima', 'Musa', 'Ngozi', 'Yusuf', 'Zainab', 'Bisi', 'Kemi', 'Tunde', 'Sola', 'Femi', 'Chika', 'Ibrahim', 'Samuel', 'David', 'Sarah', 'Grace', 'Emmanuel', 'Precious', 'Kehinde', 'Idris', 'Blessing'];
  const lastNames = ['Adeyemi', 'Okonkwo', 'Balogun', 'Ojo', 'Ibrahim', 'Mohammed', 'Eze', 'Okafor', 'Lawal', 'Bello', 'Odunsi', 'Soweto', 'Danladi', 'Okeke', 'Adebayo', 'Oni', 'Bakare', 'Cole', 'Davies', 'Ajayi', 'Nwosu', 'Danjuma', 'Bankole', 'Popoola', 'Sanni'];

  const employees: Employee[] = [];

  // 1. Add Specific Demo Characters
  employees.push(
    { id: '1', firstName: 'Tola', lastName: 'Adeyemi', email: 'tola.a@company.com', phoneNumber: '+2348012345678', designation: 'Production Supervisor', department: 'Production', basicSalary: 150000, housingAllowance: 70000, transportAllowance: 30000, pfa: 'Stanbic IBTC Pension Managers', rsaNumber: 'PEN100234', status: EmployeeStatus.ACTIVE, joinDate: '2020-01-10', cooperativeLoanBalance: 0, faceVerified: true },
    { id: '2', firstName: 'Chinedu', lastName: 'Okonkwo', email: 'chinedu.o@company.com', phoneNumber: '+2348098765432', designation: 'Machine Operator', department: 'Production', basicSalary: 80000, housingAllowance: 30000, transportAllowance: 20000, pfa: 'ARM Pension Managers', rsaNumber: 'PEN100555', status: EmployeeStatus.ACTIVE, joinDate: '2021-05-15', cooperativeLoanBalance: 50000, faceVerified: true },
    { id: '3', firstName: 'Segun', lastName: 'Balogun', email: 'segun.b@company.com', phoneNumber: '+2348055555555', designation: 'Factory Worker', department: 'Production', basicSalary: 70000, housingAllowance: 25000, transportAllowance: 15000, pfa: 'Stanbic IBTC Pension Managers', rsaNumber: 'PEN100999', status: EmployeeStatus.ACTIVE, joinDate: '2022-02-01', cooperativeLoanBalance: 0, faceVerified: false }
  );

  // 2. Generate remaining to reach 250
  for (let i = 4; i <= 250; i++) {
    const fn = firstNames[Math.floor(Math.random() * firstNames.length)];
    const ln = lastNames[Math.floor(Math.random() * lastNames.length)];
    const dept = departments[Math.floor(Math.random() * departments.length)];
    const desig = designations[Math.floor(Math.random() * designations.length)];
    const pfa = pfas[Math.floor(Math.random() * pfas.length)];

    // Random salary between 60k and 450k basic
    const basic = Math.floor(Math.random() * (450000 - 60000) + 60000);
    const housing = Math.floor(basic * 0.4); // 40% of basic
    const transport = Math.floor(basic * 0.2); // 20% of basic

    employees.push({
      id: i.toString(),
      firstName: fn,
      lastName: ln,
      email: `${fn.toLowerCase()}.${ln.toLowerCase()}${i}@company.com`,
      phoneNumber: `+23480${Math.floor(Math.random() * 90000000) + 10000000}`,
      designation: desig,
      department: dept,
      basicSalary: basic,
      housingAllowance: housing,
      transportAllowance: transport,
      pfa: pfa,
      rsaNumber: `PEN${Math.floor(Math.random() * 899999) + 100000}`,
      status: Math.random() > 0.95 ? EmployeeStatus.RESIGNED : EmployeeStatus.ACTIVE, // 5% resigned
      joinDate: '2022-06-15',
      cooperativeLoanBalance: Math.random() > 0.8 ? Math.floor(Math.random() * 200000) : 0, // 20% have loans
      faceVerified: Math.random() > 0.1 // 90% verified
    });
  }

  // 3. Generate Historical Payroll Run (Nov 2023)
  const entries: PayrollEntry[] = employees.map(emp => {
      // Simulate that some active employees might have been resigned last month (unlikely) or just different values
      // For simplicity, we calculate based on current stats but maybe 10% less overtime
      return calculatePayrollEntry(emp, 0, 0, 0); 
  });

  const totalPayout = entries.reduce((acc, curr) => acc + curr.netPay, 0);
  const totalTax = entries.reduce((acc, curr) => acc + curr.taxPAYE, 0);
  const totalPension = entries.reduce((acc, curr) => acc + curr.pensionEmployee + curr.pensionEmployer, 0);

  const historicalRun: PayrollRun = {
    id: 'run-nov-2023',
    month: '2023-11',
    status: 'Finalized',
    dateCreated: '2023-11-28T14:30:00.000Z',
    entries: entries,
    totalPayout,
    totalTax,
    totalPension
  };

  return { employees, payrollRuns: [historicalRun] };
};

const INITIAL_AUDIT_LOGS: AuditLogEntry[] = [
    { id: 'log-1', timestamp: '2023-11-28T14:30:00.000Z', action: 'Payroll Finalized', user: 'Mr. Adebayo', details: 'Finalized payroll for November 2023.', category: 'Payroll' },
    { id: 'log-2', timestamp: '2023-11-20T10:15:00.000Z', action: 'Employee Update', user: 'Mr. Adebayo', details: 'Updated housing allowance for Tola Adeyemi to ₦70,000', category: 'Employee' },
    { id: 'log-3', timestamp: '2023-11-15T09:00:00.000Z', action: 'System Init', user: 'System', details: 'System initialized and compliance tables updated', category: 'System' },
];

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState('dashboard');

  // Use useMemo so we don't regenerate 250 employees on every render
  const { employees: initialEmployees, payrollRuns: initialRuns } = useMemo(() => generateDummyData(), []);

  const [employees, setEmployees] = useState<Employee[]>(initialEmployees);
  const [payrollRuns, setPayrollRuns] = useState<PayrollRun[]>(initialRuns);
  const [auditLogs, setAuditLogs] = useState<AuditLogEntry[]>(INITIAL_AUDIT_LOGS);

  const addAuditLog = (action: string, details: string, category: AuditLogEntry['category']) => {
    const newLog: AuditLogEntry = {
        id: crypto.randomUUID(),
        timestamp: new Date().toISOString(),
        user: 'Mr. Adebayo', // Hardcoded for demo
        action,
        details,
        category
    };
    setAuditLogs(prev => [newLog, ...prev]);
  };

  const renderContent = () => {
    switch (currentView) {
      case 'dashboard':
        return <Dashboard employees={employees} payrollRuns={payrollRuns} />;
      case 'employees':
        return <EmployeeManager employees={employees} setEmployees={setEmployees} addAuditLog={addAuditLog} />;
      case 'payroll':
        return <PayrollProcessor employees={employees} payrollRuns={payrollRuns} setPayrollRuns={setPayrollRuns} addAuditLog={addAuditLog} />;
      case 'forecasting':
        return <Forecasting employees={employees} payrollRuns={payrollRuns} />;
      case 'reports':
        return <Reports payrollRuns={payrollRuns} />;
      case 'audit':
        return <GeminiAudit payrollRuns={payrollRuns} />;
      case 'audit-logs':
        return <AuditLogViewer logs={auditLogs} />;
      case 'portal':
        return <EmployeePortal employees={employees} payrollRuns={payrollRuns} />;
      default:
        return <Dashboard employees={employees} payrollRuns={payrollRuns} />;
    }
  };

  return (
    <div className="flex h-screen bg-slate-50">
      <Sidebar currentView={currentView} setCurrentView={setCurrentView} />
      <main className="flex-1 ml-64 h-full overflow-hidden">
        {renderContent()}
      </main>
    </div>
  );
};

export default App;

