  const [variableInputs, setVariableInputs] = useState<Record<string, { overtime: number, bonus: number, loanPaid: number }>>({});

  // Blocking State
  const [blockingExplanation, setBlockingExplanation] = useState<string | null>(null);
  const [isAnalyzingBlock, setIsAnalyzingBlock] = useState(false);

  // Validation State
  const [validationStatus, setValidationStatus] = useState<'valid' | 'issues' | null>(null);

  // WhatsApp Alert Bot State
  const [showWhatsAppModal, setShowWhatsAppModal] = useState(false);
  const [sendingProgress, setSendingProgress] = useState(0);
  const [sentCount, setSentCount] = useState(0);

  useEffect(() => {
    // Check if run exists
    const existingRun = payrollRuns.find(r => r.month === selectedMonth);
    setCurrentRun(existingRun || null);
    if (existingRun) {
        setValidationStatus('valid'); // Assume finalized runs are valid
    } else {
        setValidationStatus(null);
    }
  }, [selectedMonth, payrollRuns]);

  const calculateEntries = () => {
      return employees.map(emp => {
      // Feature: Stop salary for resigned employees automatically
      // If status is RESIGNED, we return a zeroed entry to ensure they are not paid
      // unless specifically manually overridden later (which would be caught by anomaly detection)
      if (emp.status === EmployeeStatus.RESIGNED) {
          return {
              employeeId: emp.id,
              employeeName: `${emp.firstName} ${emp.lastName}`,
              employeeStatus: emp.status,
              basic: 0, housing: 0, transport: 0, grossIncome: 0, overtime: 0, bonuses: 0,
              pensionEmployee: 0, pensionEmployer: 0, taxPAYE: 0, loanDeduction: 0, otherDeductions: 0,
              totalDeductions: 0, netPay: 0, isBiometricVerified: emp.faceVerified
          };
      }

      const inputs = variableInputs[emp.id] || { overtime: 0, bonus: 0, loanPaid: 0 };
      return calculatePayrollEntry(emp, inputs.overtime, inputs.bonus, inputs.loanPaid);
    });
  }

  const validateRun = (entries: PayrollEntry[]) => {
    const ghostWorkers = entries.filter(e => e.employeeStatus === EmployeeStatus.RESIGNED && e.netPay > 0);
    const unverified = entries.filter(e => !e.isBiometricVerified && e.employeeStatus === EmployeeStatus.ACTIVE);

    return {
        ghostWorkers,
        unverified,
        hasIssues: ghostWorkers.length > 0 || unverified.length > 0
    };
  };

  const handleRunPayroll = () => {
    const entries = calculateEntries();

    const totalPayout = entries.reduce((acc, curr) => acc + curr.netPay, 0);
    const totalTax = entries.reduce((acc, curr) => acc + curr.taxPAYE, 0);
    const totalPension = entries.reduce((acc, curr) => acc + curr.pensionEmployee + curr.pensionEmployer, 0);

    const newRun: PayrollRun = {
      id: crypto.randomUUID(),
      month: selectedMonth,
      status: 'Draft',
      entries,
      totalPayout,
      totalTax,
      totalPension,
      dateCreated: new Date().toISOString()
    };

    setCurrentRun(newRun);
    setBlockingExplanation(null); 

    // Auto-Validate
    const { hasIssues } = validateRun(entries);
    setValidationStatus(hasIssues ? 'issues' : 'valid');

    addAuditLog('Run Payroll Draft', `Generated draft payroll for ${selectedMonth}. Total Estimate: ₦${totalPayout.toLocaleString()}`, 'Payroll');
  };

  const handleFinalize = async () => {
    if (!currentRun) return;

    const { ghostWorkers, unverified } = validateRun(currentRun.entries);
    const issues = [];

    if (ghostWorkers.length > 0) {
      issues.push({
        type: "Ghost Worker Detected",
        details: ghostWorkers.map(e => `${e.employeeName} is marked RESIGNED but has calculated Net Pay of ₦${e.netPay.toLocaleString()}.`)
      });
    }

    if (unverified.length > 0) {
      issues.push({
        type: "Biometric Verification Missing",
        details: unverified.map(e => `${e.employeeName} is ACTIVE but has no face biometrics enrolled.`)
      });
    }

    // If issues exist, BLOCK and EXPLAIN
    if (issues.length > 0) {
      setIsAnalyzingBlock(true);
      const explanation = await explainPayrollBlock(issues);
      setBlockingExplanation(explanation);
      addAuditLog('Compliance Block', `Payroll Finalization Blocked for ${selectedMonth} due to ${issues.length} compliance issues.`, 'Compliance');
      setIsAnalyzingBlock(false);
      return; // STOP execution
    }

    const finalRun = { ...currentRun, status: 'Finalized' as const };
    const otherRuns = payrollRuns.filter(r => r.month !== selectedMonth);
    setPayrollRuns([...otherRuns, finalRun]);
    setCurrentRun(finalRun);

    addAuditLog('Payroll Finalized', `Successfully finalized payroll for ${selectedMonth}. Total Payout: ₦${finalRun.totalPayout.toLocaleString()}`, 'Payroll');

    alert("Payroll finalized successfully!");
  };

  const startWhatsAppBroadcast = () => {
    if (!currentRun) return;
    setShowWhatsAppModal(true);
    setSendingProgress(0);
    setSentCount(0);

    // Simulate sending delay
    const total = currentRun.entries.length;
    let current = 0;

    addAuditLog('WhatsApp Broadcast', `Started payslip distribution for ${selectedMonth} via WhatsApp.`, 'System');

    const interval = setInterval(() => {
        current += 1;
        setSentCount(current);
        setSendingProgress((current / total) * 100);

        if (current >= total) {
            clearInterval(interval);
        }
    }, 600); // 600ms per employee
  };

  const updateVariableInput = (id: string, field: 'overtime' | 'bonus' | 'loanPaid', value: number) => {
    setVariableInputs(prev => ({
      ...prev,
      [id]: {
        ...prev[id] || { overtime: 0, bonus: 0, loanPaid: 0 },
        [field]: value
      }
    }));
  };

  return (
    <div className="p-6 relative pb-24 text-slate-900 dark:text-slate-100">
       <div className="flex justify-between items-center mb-6">
        <div>
          <h2 className="text-2xl font-bold text-slate-800 dark:text-white">Run Payroll</h2>
          <p className="text-slate-500 dark:text-slate-400">Calculate salaries, taxes, and deductions for {selectedMonth}.</p>
        </div>
        <div className="flex items-center gap-3">
            <input 
              type="month" 
              className="border p-2 rounded-lg bg-white dark:bg-slate-800 dark:border-slate-600 dark:text-white shadow-sm"
              value={selectedMonth}
              onChange={(e) => setSelectedMonth(e.target.value)}
            />
            {currentRun && currentRun.status === 'Draft' && (
               <button 
                onClick={handleRunPayroll}
                className="text-blue-600 dark:text-blue-400 hover:bg-blue-50 dark:hover:bg-blue-900/20 px-4 py-2 rounded-lg flex items-center gap-2 transition font-medium"
              >
                <RefreshCw size={18} /> Re-Run Calculation
              </button>
            )}
        </div>
      </div>

      {!currentRun && (
        <div className="bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-slate-200 dark:border-slate-700 p-16 flex flex-col items-center justify-center text-center max-w-2xl mx-auto mt-10">
            <div className="bg-blue-100 dark:bg-blue-900/50 p-6 rounded-full text-blue-600 dark:text-blue-400 mb-6 shadow-inner">
              <Play size={48} fill="currentColor" />
            </div>
            <h3 className="text-2xl font-bold text-slate-800 dark:text-white">Ready to Process Payroll</h3>
            <p className="text-slate-500 dark:text-slate-400 mt-2 mb-8 max-w-md">
              Click below to automatically calculate deductions, validate compliance, and check for ghost workers for <strong>{selectedMonth}</strong>.
            </p>
            <button 
              onClick={handleRunPayroll}
              className="bg-blue-600 hover:bg-blue-700 text-white text-lg font-bold px-8 py-4 rounded-xl shadow-lg hover:shadow-blue-500/30 transition transform hover:-translate-y-1 flex items-center gap-3"
            >
               Run Payroll for {selectedMonth}
            </button>
        </div>
      )}

      {currentRun && (
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">

          {/* Finalized Action Banner */}
          {currentRun.status === 'Finalized' && (
             <div className="bg-green-50 dark:bg-green-900/20 p-4 rounded-xl border border-green-200 dark:border-green-800 flex items-center justify-between">
                <div className="flex items-center gap-3">
                    <div className="bg-green-100 dark:bg-green-900/50 p-2 rounded-full text-green-700 dark:text-green-400">
                        <CheckCircle2 size={24} />
                    </div>
                    <div>
                        <h4 className="font-bold text-lg text-green-900 dark:text-green-300">Payroll is Finalized</h4>
                        <p className="text-sm text-green-700 dark:text-green-400">All data is locked and reports are ready for distribution.</p>
                    </div>
                </div>
                <div className="flex gap-2">
                    <button 
                      onClick={startWhatsAppBroadcast}
                      className="bg-green-600 text-white px-5 py-2.5 rounded-lg font-bold shadow-sm hover:bg-green-700 transition flex items-center gap-2"
                    >
                        <MessageCircle size={18} /> Send WhatsApp Alerts
                    </button>
                </div>
             </div>
          )}

          {/* Validation Status Banner (Only for Draft) */}
          {currentRun.status === 'Draft' && (
             <div className={`p-4 rounded-xl border flex items-start gap-4 ${
                 validationStatus === 'issues' 
                 ? 'bg-red-50 dark:bg-red-900/20 border-red-200 dark:border-red-800 text-red-900 dark:text-red-200' 
                 : 'bg-slate-50 dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-700 dark:text-slate-300'
             }`}>
                <div className={`p-2 rounded-full ${validationStatus === 'issues' ? 'bg-red-100 dark:bg-red-900/50 text-red-600 dark:text-red-400' : 'bg-green-100 dark:bg-green-900/50 text-green-600 dark:text-green-400'}`}>
                    {validationStatus === 'issues' ? <AlertCircle size={24} /> : <CheckCircle2 size={24} />}
                </div>
                <div className="flex-1">
                    <h4 className="font-bold text-lg">
                        {validationStatus === 'issues' ? 'Compliance Issues Detected' : 'Data Validation Passed'}
                    </h4>
                    <p className="text-sm opacity-90 mt-1">
                        {validationStatus === 'issues' 
                           ? 'The system has flagged potential ghost workers or unverified employees. Please review the highlighted entries below before finalizing.'
                           : 'All calculations are complete. No ghost workers or compliance risks detected.'
                        }
                    </p>
                </div>
                {validationStatus === 'valid' && (
                    <button 
                        onClick={handleFinalize}
                        className="bg-green-600 text-white px-6 py-2 rounded-lg font-bold shadow-sm hover:bg-green-700 transition flex items-center gap-2"
                    >
                        <Save size={18} /> Finalize Run
                    </button>
                )}
                {validationStatus === 'issues' && (
                    <button 
                        onClick={handleFinalize}
                        className="bg-red-600 text-white px-6 py-2 rounded-lg font-bold shadow-sm hover:bg-red-700 transition flex items-center gap-2"
                    >
                        Review & Resolve
                    </button>
                )}
             </div>
          )}

          {/* Summary Cards */}
          <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
            <div className="bg-white dark:bg-slate-800 p-4 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm">
              <p className="text-sm text-slate-500 dark:text-slate-400">Total Net Payout</p>
              <p className="text-2xl font-bold text-slate-900 dark:text-white">₦{currentRun.totalPayout.toLocaleString(undefined, { maximumFractionDigits: 0 })}</p>
            </div>
             <div className="bg-white dark:bg-slate-800 p-4 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm">
              <p className="text-sm text-slate-500 dark:text-slate-400">Total PAYE Tax</p>
              <p className="text-2xl font-bold text-blue-600 dark:text-blue-400">₦{currentRun.totalTax.toLocaleString(undefined, { maximumFractionDigits: 0 })}</p>
            </div>
             <div className="bg-white dark:bg-slate-800 p-4 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm">
              <p className="text-sm text-slate-500 dark:text-slate-400">Total Pension Remittance</p>
              <p className="text-2xl font-bold text-purple-600 dark:text-purple-400">₦{currentRun.totalPension.toLocaleString(undefined, { maximumFractionDigits: 0 })}</p>
            </div>
             <div className="bg-white dark:bg-slate-800 p-4 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm flex flex-col justify-center">
                <div className="flex items-center gap-2 text-sm text-slate-500 dark:text-slate-400 mb-1">
                    <FileCheck size={16} /> Reports Ready
                </div>
                <div className="flex gap-2">
                    <span className="text-xs bg-slate-100 dark:bg-slate-700 text-slate-600 dark:text-slate-300 px-2 py-1 rounded">PAYE</span>
                    <span className="text-xs bg-slate-100 dark:bg-slate-700 text-slate-600 dark:text-slate-300 px-2 py-1 rounded">Pension</span>
                    <span className="text-xs bg-slate-100 dark:bg-slate-700 text-slate-600 dark:text-slate-300 px-2 py-1 rounded">Bank</span>
                </div>
            </div>
          </div>

          {/* Payroll Table */}
          <div className="bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-slate-200 dark:border-slate-700 overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-left text-sm">
                <thead className="bg-slate-50 dark:bg-slate-900/50 text-slate-600 dark:text-slate-300 font-medium border-b border-slate-200 dark:border-slate-700">
                  <tr>
                    <th className="px-4 py-3">Employee</th>
                    <th className="px-4 py-3">Status</th>
                    <th className="px-4 py-3">Verification</th>
                    <th className="px-4 py-3">Basic + Allowances</th>
                    <th className="px-4 py-3 w-32">Overtime (₦)</th>
                    <th className="px-4 py-3">Gross</th>
                    <th className="px-4 py-3">Deductions</th>
                    <th className="px-4 py-3 bg-slate-100 dark:bg-slate-700 font-bold">Net Pay</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 dark:divide-slate-700">
                  {currentRun.entries.map((entry) => {
                    const isGhostRisk = entry.employeeStatus === EmployeeStatus.RESIGNED && entry.netPay > 0;
                    const isBiometricRisk = !entry.isBiometricVerified && entry.employeeStatus === EmployeeStatus.ACTIVE;
                    const hasError = isGhostRisk || isBiometricRisk;

                    return (
                      <tr key={entry.employeeId} className={`hover:bg-slate-50 dark:hover:bg-slate-700 transition ${hasError ? 'bg-red-50/70 dark:bg-red-900/20' : ''}`}>
                        <td className="px-4 py-3 font-medium text-slate-900 dark:text-white">
                          {entry.employeeName}
                          {isGhostRisk && (
                            <div className="flex items-center gap-1 text-xs text-red-600 dark:text-red-400 font-bold mt-1 animate-pulse">
                              <AlertCircle size={12} /> GHOST WORKER DETECTED
                            </div>
                          )}
                          {isBiometricRisk && (
                             <div className="flex items-center gap-1 text-xs text-red-600 dark:text-red-400 font-bold mt-1">
                              <ShieldAlert size={12} /> IDENTITY UNVERIFIED
                            </div>
                          )}
                        </td>
                        <td className="px-4 py-3 text-xs text-slate-600 dark:text-slate-300">{entry.employeeStatus}</td>
                        <td className="px-4 py-3">
                          {entry.isBiometricVerified ? (
                            <span className="text-green-600 dark:text-green-400 flex items-center gap-1 text-xs font-bold"><ScanFace size={14}/> Verified</span>
                          ) : (
                            <span className="text-red-500 dark:text-red-400 flex items-center gap-1 text-xs font-bold"><ShieldAlert size={14}/> Missing</span>
                          )}
                        </td>
                        <td className="px-4 py-3 text-slate-700 dark:text-slate-300">₦{(entry.basic + entry.housing + entry.transport).toLocaleString()}</td>

                        {/* Inputs: Editable only if Draft */}
                        <td className="px-4 py-3">
                           {currentRun.status === 'Draft' ? (
                             <input 
                              type="number" 
                              className="w-full border dark:border-slate-600 bg-white dark:bg-slate-700 text-slate-900 dark:text-white rounded p-1 text-right focus:ring-2 focus:ring-blue-500 outline-none"
                              value={variableInputs[entry.employeeId]?.overtime || 0}
                              onChange={(e) => updateVariableInput(entry.employeeId, 'overtime', Number(e.target.value))}
                              disabled={entry.employeeStatus === EmployeeStatus.RESIGNED}
                            />
                           ) : (
                             <span className="text-slate-700 dark:text-slate-300">₦{entry.overtime.toLocaleString()}</span>
                           )}
                        </td>

                        <td className="px-4 py-3 font-medium text-slate-900 dark:text-white">₦{entry.grossIncome.toLocaleString()}</td>
                        <td className="px-4 py-3 text-red-600 dark:text-red-400 text-xs">
                          <div>Tax: ₦{entry.taxPAYE.toLocaleString(undefined, { maximumFractionDigits: 0 })}</div>
                          <div>Pension: ₦{(entry.pensionEmployee + entry.pensionEmployer).toLocaleString(undefined, { maximumFractionDigits: 0 })}</div>
                        </td>
                        <td className="px-4 py-3 font-bold text-slate-900 dark:text-white bg-slate-50 dark:bg-slate-700 border-l dark:border-slate-700">
                          ₦{entry.netPay.toLocaleString(undefined, { maximumFractionDigits: 0 })}
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
             <div className="p-4 bg-slate-50 dark:bg-slate-800 border-t border-slate-200 dark:border-slate-700 text-xs text-slate-500 dark:text-slate-400 flex justify-between items-center">
                <span>* Pension: 8% Employee + 10% Employer. Tax: PITA Bands applies.</span>
                {currentRun.status === 'Draft' && (
                  <span className="text-amber-600 dark:text-amber-400 font-medium">Draft Mode - Values not final. Edit Overtime/Bonuses above if needed.</span>
                )}
            </div>
          </div>
        </div>
      )}

      {/* Compliance Blocking Modal */}
      {(isAnalyzingBlock || blockingExplanation) && (
        <div className="fixed inset-0 bg-black/70 flex items-center justify-center z-50 backdrop-blur-sm">
          <div className="bg-white dark:bg-slate-800 rounded-xl shadow-2xl w-full max-w-2xl overflow-hidden border-2 border-red-500 animate-in fade-in zoom-in duration-300">

             {/* Header */}
             <div className="bg-red-50 dark:bg-red-900/30 p-6 border-b border-red-100 dark:border-red-900/50 flex items-center justify-between">
                <div className="flex items-center gap-3">
                   <div className="bg-red-100 dark:bg-red-900/50 p-2 rounded-full text-red-600 dark:text-red-400">
                      <ShieldAlert size={32} />
                   </div>
                   <div>
                     <h3 className="text-xl font-bold text-slate-900 dark:text-white">Payroll Finalization Blocked</h3>
                     <p className="text-sm text-red-600 dark:text-red-400 font-medium">Compliance Intervention Required</p>
                   </div>
                </div>
                <button onClick={() => setBlockingExplanation(null)} className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200">
                  <XCircle size={24} />
                </button>
             </div>

             {/* Content */}
             <div className="p-6 max-h-[60vh] overflow-y-auto">
               {isAnalyzingBlock ? (
                 <div className="flex flex-col items-center justify-center py-12">
                   <Loader2 className="animate-spin text-red-500 mb-4" size={48} />
                   <h4 className="text-lg font-semibold text-slate-700 dark:text-slate-300">Analyzing Risk Factors...</h4>
                   <p className="text-sm text-slate-500 dark:text-slate-400">Consulting AI Compliance Engine</p>
                 </div>
               ) : (
                 <div className="prose prose-sm prose-red dark:prose-invert max-w-none">
                    <div className="flex items-center gap-2 mb-4 text-slate-800 dark:text-slate-200 font-bold bg-slate-100 dark:bg-slate-700 p-3 rounded-lg border border-slate-200 dark:border-slate-600">
                      <Bot size={20} className="text-purple-600 dark:text-purple-400" />
                      <span>Explainable AI Report:</span>
                    </div>
                    <ReactMarkdown className="dark:text-slate-300">{blockingExplanation || ""}</ReactMarkdown>
                 </div>
               )}
             </div>

             {/* Footer */}
             <div className="p-4 bg-slate-50 dark:bg-slate-900 border-t dark:border-slate-700 flex justify-end">
               <button 
                onClick={() => setBlockingExplanation(null)}
                className="bg-slate-900 dark:bg-slate-700 text-white px-6 py-2 rounded-lg font-medium hover:bg-slate-800 dark:hover:bg-slate-600 transition"
               >
                 Acknowledge & Fix
               </button>
             </div>
          </div>
        </div>
      )}

      {/* WhatsApp Broadcast Modal */}
      {showWhatsAppModal && (
        <div className="fixed inset-0 bg-black/70 flex items-center justify-center z-50 backdrop-blur-sm">
           <div className="bg-white dark:bg-slate-800 rounded-xl shadow-2xl w-full max-w-md overflow-hidden border border-slate-200 dark:border-slate-700">
             <div className="bg-[#25D366] p-6 text-white flex items-center gap-3">
                <MessageCircle size={32} />
                <div>
                   <h3 className="text-xl font-bold">WhatsApp Bot</h3>
                   <p className="text-white/80 text-sm">Distributing Payslips & Alerts</p>
                </div>
             </div>

             <div className="p-8">
                {sendingProgress < 100 ? (
                    <div className="text-center">
                        <div className="mb-4 relative h-3 bg-slate-100 dark:bg-slate-700 rounded-full overflow-hidden">
                           <div className="absolute top-0 left-0 h-full bg-[#25D366] transition-all duration-300" style={{ width: `${sendingProgress}%`}}></div>
                        </div>
                        <h4 className="text-lg font-bold text-slate-800 dark:text-white mb-1">Sending Alerts...</h4>
                        <p className="text-slate-500 dark:text-slate-400 text-sm">Notifying {sentCount} of {currentRun?.entries.length} employees</p>

                        <div className="mt-6 bg-slate-50 dark:bg-slate-700 p-4 rounded-lg border border-slate-100 dark:border-slate-600 text-left">
                            <p className="text-xs text-slate-400 mb-2 font-mono">DEBUG: WHATSAPP_API_STREAM</p>
                            <p className="text-xs text-slate-600 dark:text-slate-300 font-mono line-clamp-3">
                                {'>'} Initializing secure session... <br/>
                                {'>'} Template: PAYSLIP_ALERT_V2 <br/>
                                {'>'} Dispatching to {currentRun?.entries[Math.min(sentCount, (currentRun?.entries.length || 1) - 1)].employeeName}...
                            </p>
                        </div>
                    </div>
                ) : (
                    <div className="text-center">
                        <div className="w-16 h-16 bg-green-100 dark:bg-green-900/30 text-green-600 dark:text-green-400 rounded-full flex items-center justify-center mx-auto mb-4 animate-bounce">
                           <CheckCircle2 size={32} />
                        </div>
                        <h4 className="text-xl font-bold text-slate-800 dark:text-white">Broadcast Complete</h4>
                        <p className="text-slate-500 dark:text-slate-400 mt-2 mb-6">
                           Successfully sent {currentRun?.entries.length} payslips and payment alerts via WhatsApp.
                        </p>
                        <button 
                          onClick={() => setShowWhatsAppModal(false)}
                          className="bg-slate-900 dark:bg-slate-700 text-white w-full py-3 rounded-lg font-bold hover:bg-slate-800 dark:hover:bg-slate-600 mb-3"
                        >
                           Close
                        </button>

                        <button 
                            onClick={() => {
                                if (!currentRun) return;
                                const msg = `Payroll Run ${currentRun.month} Completed.\nTotal Payout: ₦${currentRun.totalPayout.toLocaleString()}\nStaff Count: ${currentRun.entries.length}\nStatus: Finalized & Disbursed.`;
                                window.open(`https://wa.me/?text=${encodeURIComponent(msg)}`, '_blank');
                            }}
                            className="w-full border border-slate-300 dark:border-slate-600 text-slate-700 dark:text-slate-300 py-3 rounded-lg font-bold hover:bg-slate-50 dark:hover:bg-slate-700 flex items-center justify-center gap-2"
                        >
                            <Send size={18} /> Share Summary with Director
                        </button>
                    </div>
                )}
             </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default PayrollProcessor;

import React, { useState, useRef, useEffect } from 'react';
import { Employee, EmployeeStatus, AuditLogEntry } from '../types';
import { Plus, Search, Edit2, UserMinus, UserCheck, ScanFace, Camera, Upload, CheckCircle, X, Calculator, Calendar } from 'lucide-react';

interface EmployeeManagerProps {
  employees: Employee[];
  setEmployees: React.Dispatch<React.SetStateAction<Employee[]>>;
  addAuditLog: (action: string, details: string, category: AuditLogEntry['category']) => void;
}

const EmployeeManager: React.FC<EmployeeManagerProps> = ({ employees, setEmployees, addAuditLog }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [showModal, setShowModal] = useState(false);
  const [showBiometricModal, setShowBiometricModal] = useState(false);
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);

  // Offboarding State
  const [showOffboardModal, setShowOffboardModal] = useState(false);
  const [offboardDate, setOffboardDate] = useState(new Date().toISOString().split('T')[0]);
  const [offboardReason, setOffboardReason] = useState('Resignation');

  // Biometric State
  const [biometricStep, setBiometricStep] = useState<'start' | 'scanning' | 'processing' | 'success'>('start');
  const videoRef = useRef<HTMLVideoElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);

  // Initial State for form
  const initialFormState: Employee = {
    id: '',
    firstName: '',
    lastName: '',
    email: '',
    phoneNumber: '',
    designation: '',
    department: '',
    basicSalary: 0,
    housingAllowance: 0,
    transportAllowance: 0,
    pfa: 'Stanbic IBTC Pension Managers',
    rsaNumber: '',
    status: EmployeeStatus.ACTIVE,
    joinDate: new Date().toISOString().split('T')[0],
    cooperativeLoanBalance: 0,
    faceVerified: false
  };

  const [formData, setFormData] = useState<Employee>(initialFormState);

  // Fix: Attach stream to video element whenever step becomes 'scanning' and stream is available
  useEffect(() => {
    if (biometricStep === 'scanning' && stream && videoRef.current) {
      videoRef.current.srcObject = stream;
    }
  }, [biometricStep, stream]);

  // Fix: Cleanup stream on unmount
  useEffect(() => {
    return () => {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, []); // Empty dependency array for unmount cleanup only, specific cleanup is handled in stopCamera

  const handleSave = () => {
    if (editingEmployee) {
      // Logic for Audit: Check if salary changed
      const salaryChanged = editingEmployee.basicSalary !== formData.basicSalary;
      const allowanceChanged = (editingEmployee.housingAllowance !== formData.housingAllowance) || (editingEmployee.transportAllowance !== formData.transportAllowance);

      if (salaryChanged) {
          addAuditLog('Salary Update', `Changed Basic Salary for ${formData.firstName} ${formData.lastName} from ₦${editingEmployee.basicSalary.toLocaleString()} to ₦${formData.basicSalary.toLocaleString()}`, 'Employee');
      } else if (allowanceChanged) {
          addAuditLog('Allowance Update', `Updated allowances for ${formData.firstName} ${formData.lastName}`, 'Employee');
      } else {
          addAuditLog('Profile Update', `Updated profile details for ${formData.firstName} ${formData.lastName}`, 'Employee');
      }

      setEmployees(prev => prev.map(emp => emp.id === editingEmployee.id ? { ...formData, id: emp.id } : emp));
    } else {
      const newEmployee = { ...formData, id: crypto.randomUUID() };
      setEmployees(prev => [...prev, newEmployee]);
      addAuditLog('Employee Onboarding', `Added new employee: ${formData.firstName} ${formData.lastName} (${formData.designation})`, 'Employee');
    }
    setShowModal(false);
    setEditingEmployee(null);
    setFormData(initialFormState);
  };

  const handleEdit = (employee: Employee) => {
    setEditingEmployee(employee);
    setFormData(employee);
    setShowModal(true);
  };

  const handleEnrollFace = (employee: Employee) => {
    setEditingEmployee(employee);
    setBiometricStep('start');
    setShowBiometricModal(true);
  };

  const initiateOffboard = (employee: Employee) => {
    setEditingEmployee(employee);
    setOffboardDate(new Date().toISOString().split('T')[0]);
    setShowOffboardModal(true);
  };

  const confirmOffboard = () => {
    if (editingEmployee) {
        setEmployees(prev => prev.map(emp => emp.id === editingEmployee.id ? { 
            ...emp, 
            status: EmployeeStatus.RESIGNED,
            exitDate: offboardDate 
        } : emp));

        addAuditLog('Employee Offboarding', `Offboarded ${editingEmployee.firstName} ${editingEmployee.lastName}. Reason: ${offboardReason}. Exit Date: ${offboardDate}`, 'Employee');

        setShowOffboardModal(false);
        setEditingEmployee(null);
    }
  };

  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({ video: true });
      setStream(mediaStream);
      setBiometricStep('scanning');
      // Note: We do not set videoRef.current.srcObject here because the video element 
      // is not yet rendered. The useEffect above handles it.
    } catch (err) {
      console.error(err);
      alert("Camera access denied or unavailable. Please use upload.");
    }
  };

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
  };

  const captureAndVerify = () => {
    setBiometricStep('processing');
    stopCamera();
    // Simulate API delay
    setTimeout(() => {
      if (editingEmployee) {
         setEmployees(prev => prev.map(emp => emp.id === editingEmployee.id ? { ...emp, faceVerified: true } : emp));
         addAuditLog('Biometric Verification', `Successfully enrolled face biometrics for ${editingEmployee.firstName} ${editingEmployee.lastName}`, 'Compliance');
      }
      setBiometricStep('success');
    }, 2000);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setBiometricStep('processing');
      // Simulate upload and processing
      setTimeout(() => {
        if (editingEmployee) {
           setEmployees(prev => prev.map(emp => emp.id === editingEmployee.id ? { ...emp, faceVerified: true } : emp));
           addAuditLog('Biometric Verification', `Enrolled face biometrics via upload for ${editingEmployee.firstName} ${editingEmployee.lastName}`, 'Compliance');
        }
        setBiometricStep('success');
      }, 1500);
    }
  };

  const closeBiometricModal = () => {
    stopCamera();
    setShowBiometricModal(false);
    setEditingEmployee(null);
  };

  const reactivateEmployee = (id: string) => {
    if (confirm("Are you sure you want to reactivate this employee?")) {
        setEmployees(prev => prev.map(emp => emp.id === id ? { ...emp, status: EmployeeStatus.ACTIVE, exitDate: undefined } : emp));
        addAuditLog('Employee Reactivation', `Reactivated employee ID: ${id}`, 'Employee');
    }
  };

  const filteredEmployees = employees.filter(emp => 
    emp.firstName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.lastName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.department.toLowerCase().includes(searchTerm.toLowerCase())
  );

  // Final Pay Calculation Helper
  const getFinalPayEstimate = () => {
      if (!editingEmployee) return { days: 0, gross: 0, prorated: 0, loan: 0, final: 0 };

      const exitDay = new Date(offboardDate).getDate();
      const monthlyGross = editingEmployee.basicSalary + editingEmployee.housingAllowance + editingEmployee.transportAllowance;
      const dailyRate = monthlyGross / 30; // Using 30 days as standard basis
      const proratedSalary = dailyRate * exitDay;
      const loan = editingEmployee.cooperativeLoanBalance;
      const final = Math.max(0, proratedSalary - loan);

      return {
          days: exitDay,
          gross: monthlyGross,
          prorated: proratedSalary,
          loan: loan,
          final: final
      };
  };

  const finalPay = getFinalPayEstimate();

  return (
    <div className="p-6 text-slate-900 dark:text-slate-100">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h2 className="text-2xl font-bold text-slate-800 dark:text-white">Employee Management</h2>
          <p className="text-slate-500 dark:text-slate-400">Manage your workforce, statuses, and biometric data.</p>
        </div>
        <button 
          onClick={() => { setEditingEmployee(null); setFormData(initialFormState); setShowModal(true); }}
          className="bg-green-600 hover:bg-green-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition"
        >
          <Plus size={18} /> Add Employee
        </button>
      </div>

      <div className="bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-slate-200 dark:border-slate-700 overflow-hidden">
        <div className="p-4 border-b border-slate-200 dark:border-slate-700 flex gap-4">
          <div className="relative flex-1 max-w-md">
            <Search className="absolute left-3 top-2.5 text-slate-400" size={20} />
            <input 
              type="text" 
              placeholder="Search by name or department..." 
              className="w-full pl-10 pr-4 py-2 border border-slate-300 dark:border-slate-600 rounded-lg focus:outline-none focus:ring-2 focus:ring-green-500 bg-white dark:bg-slate-700 dark:text-white"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
            <thead className="bg-slate-50 dark:bg-slate-900/50 text-slate-600 dark:text-slate-300 font-medium border-b border-slate-200 dark:border-slate-700">
              <tr>
                <th className="px-6 py-4">Name</th>
                <th className="px-6 py-4">Department</th>
                <th className="px-6 py-4">Status</th>
                <th className="px-6 py-4">Biometrics</th>
                <th className="px-6 py-4">Loan Balance</th>
                <th className="px-6 py-4 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 dark:divide-slate-700">
              {filteredEmployees.map((emp) => (
                <tr key={emp.id} className="hover:bg-slate-50 dark:hover:bg-slate-700 transition">
                  <td className="px-6 py-4">
                    <div className="font-medium text-slate-900 dark:text-white">{emp.firstName} {emp.lastName}</div>
                    <div className="text-slate-500 dark:text-slate-400 text-xs">{emp.email}</div>
                  </td>
                  <td className="px-6 py-4 text-slate-600 dark:text-slate-300">{emp.department}</td>
                  <td className="px-6 py-4">
                    <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${
                      emp.status === EmployeeStatus.ACTIVE ? 'bg-green-100 dark:bg-green-900/30 text-green-800 dark:text-green-300' :
                      emp.status === EmployeeStatus.RESIGNED ? 'bg-red-100 dark:bg-red-900/30 text-red-800 dark:text-red-300' :
                      'bg-yellow-100 dark:bg-yellow-900/30 text-yellow-800 dark:text-yellow-300'
                    }`}>
                      {emp.status}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                     {emp.faceVerified ? (
                       <div className="flex items-center gap-1 text-green-600 dark:text-green-400 bg-green-50 dark:bg-green-900/20 w-fit px-2 py-1 rounded text-xs font-medium border border-green-200 dark:border-green-800">
                         <ScanFace size={14} /> Verified
                       </div>
                     ) : (
                       <div className="flex items-center gap-1 text-slate-500 dark:text-slate-400 bg-slate-100 dark:bg-slate-700 w-fit px-2 py-1 rounded text-xs font-medium border border-slate-200 dark:border-slate-600">
                         <ScanFace size={14} /> Not Enrolled
                       </div>
                     )}
                  </td>
                  <td className="px-6 py-4 text-slate-600 dark:text-slate-300">
                     ₦{emp.cooperativeLoanBalance.toLocaleString()}
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex items-center justify-end gap-2">
                       <button 
                        onClick={() => handleEnrollFace(emp)}
                        className={`p-1.5 rounded transition ${emp.faceVerified ? 'text-green-600 bg-green-50 dark:bg-green-900/20 dark:text-green-400 hover:bg-green-100 dark:hover:bg-green-900/40' : 'text-blue-600 bg-blue-50 dark:bg-blue-900/20 dark:text-blue-400 hover:bg-blue-100 dark:hover:bg-blue-900/40'}`}
                        title="Biometric Enrollment"
                      >
                        <ScanFace size={16} />
                      </button>
                      <button 
                        onClick={() => handleEdit(emp)}
                        className="p-1.5 text-slate-500 hover:text-blue-600 hover:bg-blue-50 dark:text-slate-400 dark:hover:text-blue-400 dark:hover:bg-blue-900/30 rounded"
                        title="Edit Details"
                      >
                        <Edit2 size={16} />
                      </button>

                      {emp.status === EmployeeStatus.ACTIVE ? (
                        <button 
                          onClick={() => initiateOffboard(emp)}
                          className="p-1.5 rounded text-slate-500 hover:text-red-600 hover:bg-red-50 dark:text-slate-400 dark:hover:text-red-400 dark:hover:bg-red-900/30"
                          title="Offboard Employee (Exit)"
                        >
                          <UserMinus size={16} />
                        </button>
                      ) : (
                        <button 
                          onClick={() => reactivateEmployee(emp.id)}
                          className="p-1.5 rounded text-slate-500 hover:text-green-600 hover:bg-green-50 dark:text-slate-400 dark:hover:text-green-400 dark:hover:bg-green-900/30"
                          title="Reactivate Employee"
                        >
                          <UserCheck size={16} />
                        </button>
                      )}
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* New Employee Modal */}
      {showModal && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex items-center justify-center z-50">
          <div className="bg-white dark:bg-slate-800 rounded-xl shadow-xl p-6 w-full max-w-2xl max-h-[90vh] overflow-y-auto border border-slate-200 dark:border-slate-700">
            <h3 className="text-xl font-bold mb-4 text-slate-800 dark:text-white">{editingEmployee ? 'Edit Employee' : 'New Employee'}</h3>
            {/* ... Form Content ... */}
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700 dark:text-slate-300">First Name</label>
                <input 
                  type="text" 
                  className="w-full border dark:border-slate-600 bg-white dark:bg-slate-700 text-slate-900 dark:text-white p-2 rounded focus:ring-2 focus:ring-blue-500 outline-none" 
                  value={formData.firstName}
                  onChange={e => setFormData({...formData, firstName: e.target.value})}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700 dark:text-slate-300">Last Name</label>
                <input 
                  type="text" 
                  className="w-full border dark:border-slate-600 bg-white dark:bg-slate-700 text-slate-900 dark:text-white p-2 rounded focus:ring-2 focus:ring-blue-500 outline-none" 
                  value={formData.lastName}
                  onChange={e => setFormData({...formData, lastName: e.target.value})}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700 dark:text-slate-300">Email</label>
                <input 
                  type="email" 
                  className="w-full border dark:border-slate-600 bg-white dark:bg-slate-700 text-slate-900 dark:text-white p-2 rounded focus:ring-2 focus:ring-blue-500 outline-none" 
                  value={formData.email}
                  onChange={e => setFormData({...formData, email: e.target.value})}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700 dark:text-slate-300">Phone Number (WhatsApp)</label>
                <input 
                  type="text" 
                  className="w-full border dark:border-slate-600 bg-white dark:bg-slate-700 text-slate-900 dark:text-white p-2 rounded focus:ring-2 focus:ring-blue-500 outline-none" 
                  value={formData.phoneNumber}
                  onChange={e => setFormData({...formData, phoneNumber: e.target.value})}
                  placeholder="+234..."
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700 dark:text-slate-300">Department</label>
                <input 
                  type="text" 
                  className="w-full border dark:border-slate-600 bg-white dark:bg-slate-700 text-slate-900 dark:text-white p-2 rounded focus:ring-2 focus:ring-blue-500 outline-none" 
                  value={formData.department}
                  onChange={e => setFormData({...formData, department: e.target.value})}
                />
              </div>

              <div className="col-span-2 mt-2 pt-2 border-t border-slate-100 dark:border-slate-700">
                <h4 className="font-semibold text-sm text-slate-900 dark:text-white mb-2">Compensation (Monthly)</h4>
              </div>

              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700 dark:text-slate-300">Basic Salary (₦)</label>
                <input 
                  type="number" 
                  className="w-full border dark:border-slate-600 bg-white dark:bg-slate-700 text-slate-900 dark:text-white p-2 rounded focus:ring-2 focus:ring-blue-500 outline-none" 
                  value={formData.basicSalary}
                  onChange={e => setFormData({...formData, basicSalary: Number(e.target.value)})}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700 dark:text-slate-300">Housing Allowance (₦)</label>
                <input 
                  type="number" 
                  className="w-full border dark:border-slate-600 bg-white dark:bg-slate-700 text-slate-900 dark:text-white p-2 rounded focus:ring-2 focus:ring-blue-500 outline-none" 
                  value={formData.housingAllowance}
                  onChange={e => setFormData({...formData, housingAllowance: Number(e.target.value)})}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700 dark:text-slate-300">Transport Allowance (₦)</label>
                <input 
                  type="number" 
                  className="w-full border dark:border-slate-600 bg-white dark:bg-slate-700 text-slate-900 dark:text-white p-2 rounded focus:ring-2 focus:ring-blue-500 outline-none" 
                  value={formData.transportAllowance}
                  onChange={e => setFormData({...formData, transportAllowance: Number(e.target.value)})}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700 dark:text-slate-300">Cooperative Loan Bal (₦)</label>
                <input 
                  type="number" 
                  className="w-full border dark:border-slate-600 bg-white dark:bg-slate-700 text-slate-900 dark:text-white p-2 rounded focus:ring-2 focus:ring-blue-500 outline-none" 
                  value={formData.cooperativeLoanBalance}
                  onChange={e => setFormData({...formData, cooperativeLoanBalance: Number(e.target.value)})}
                />
              </div>

               <div className="col-span-2 mt-2 pt-2 border-t border-slate-100 dark:border-slate-700">
                <h4 className="font-semibold text-sm text-slate-900 dark:text-white mb-2">Compliance</h4>
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700 dark:text-slate-300">PFA Name</label>
                <select 
                  className="w-full border dark:border-slate-600 bg-white dark:bg-slate-700 text-slate-900 dark:text-white p-2 rounded focus:ring-2 focus:ring-blue-500 outline-none"
                  value={formData.pfa}
                  onChange={e => setFormData({...formData, pfa: e.target.value})}
                >
                  <option>Stanbic IBTC Pension Managers</option>
                  <option>ARM Pension Managers</option>
                  <option>Leadway Pensure</option>
                  <option>Fidelity Pension</option>
                  <option>Premium Pension</option>
                </select>
              </div>
               <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700 dark:text-slate-300">RSA Number</label>
                <input 
                  type="text" 
                  className="w-full border dark:border-slate-600 bg-white dark:bg-slate-700 text-slate-900 dark:text-white p-2 rounded focus:ring-2 focus:ring-blue-500 outline-none" 
                  value={formData.rsaNumber}
                  onChange={e => setFormData({...formData, rsaNumber: e.target.value})}
                />
              </div>
            </div>

            <div className="mt-6 flex justify-end gap-3">
              <button 
                onClick={() => setShowModal(false)}
                className="px-4 py-2 text-slate-600 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg transition"
              >
                Cancel
              </button>
              <button 
                onClick={handleSave}
                className="px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 shadow"
              >
                Save Employee
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Offboarding Modal */}
      {showOffboardModal && editingEmployee && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-[55]">
            <div className="bg-white dark:bg-slate-800 rounded-xl shadow-2xl p-6 w-full max-w-lg border border-slate-200 dark:border-slate-700">
                <div className="flex items-center gap-3 mb-6 pb-4 border-b dark:border-slate-700">
                    <div className="bg-red-100 dark:bg-red-900/50 p-3 rounded-full text-red-600 dark:text-red-400">
                        <UserMinus size={24} />
                    </div>
                    <div>
                        <h3 className="text-xl font-bold text-slate-900 dark:text-white">Offboard Employee</h3>
                        <p className="text-sm text-slate-500 dark:text-slate-400">Initiate exit and calculate final settlement.</p>
                    </div>
                </div>

                <div className="space-y-4">
                    <div className="bg-slate-50 dark:bg-slate-700 p-4 rounded-lg border border-slate-200 dark:border-slate-600">
                         <div className="flex justify-between mb-2">
                             <span className="text-sm text-slate-500 dark:text-slate-400">Employee</span>
                             <span className="font-bold text-slate-900 dark:text-white">{editingEmployee.firstName} {editingEmployee.lastName}</span>
                         </div>
                         <div className="flex justify-between">
                             <span className="text-sm text-slate-500 dark:text-slate-400">Department</span>
                             <span className="font-medium text-slate-700 dark:text-slate-300">{editingEmployee.department}</span>
                         </div>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-1">
                            <label className="text-xs font-bold text-slate-700 dark:text-slate-300 uppercase">Exit Date</label>
                            <input 
                              type="date" 
                              className="w-full border dark:border-slate-600 bg-white dark:bg-slate-700 text-slate-900 dark:text-white p-2 rounded-lg"
                              value={offboardDate}
                              onChange={(e) => setOffboardDate(e.target.value)}
                            />
                        </div>
                         <div className="space-y-1">
                            <label className="text-xs font-bold text-slate-700 dark:text-slate-300 uppercase">Reason</label>
                            <select 
                                className="w-full border dark:border-slate-600 bg-white dark:bg-slate-700 text-slate-900 dark:text-white p-2 rounded-lg"
                                value={offboardReason}
                                onChange={(e) => setOffboardReason(e.target.value)}
                            >
                                <option>Resignation</option>
                                <option>Termination</option>
                                <option>Retirement</option>
                                <option>Absconded</option>
                            </select>
                        </div>
                    </div>

                    <div className="bg-blue-50 dark:bg-blue-900/20 rounded-xl p-4 border border-blue-100 dark:border-blue-900/40 mt-4">
                        <h4 className="flex items-center gap-2 font-bold text-blue-800 dark:text-blue-300 mb-3">
                            <Calculator size={16} /> Final Settlement Estimate
                        </h4>
                        <div className="space-y-2 text-sm">
                            <div className="flex justify-between text-blue-900/70 dark:text-blue-300/70">
                                <span>Monthly Gross</span>
                                <span>₦{finalPay.gross.toLocaleString()}</span>
                            </div>
                            <div className="flex justify-between text-blue-900/70 dark:text-blue-300/70">
                                <span>Days Worked in Month ({finalPay.days} days)</span>
                                <span>(Prorated)</span>
                            </div>
