                        Capture & Verify
                      </button>
                   </div>
                 )}

                 {biometricStep === 'processing' && (
                   <div className="py-12 flex flex-col items-center">
                      <div className="w-12 h-12 border-4 border-blue-200 dark:border-blue-900 border-t-blue-600 dark:border-t-blue-400 rounded-full animate-spin mb-4"></div>
                      <p className="text-slate-600 dark:text-slate-300 font-medium">Processing biometrics...</p>
                      <p className="text-xs text-slate-400 mt-1">Creating secure hash</p>
                   </div>
                 )}

                 {biometricStep === 'success' && (
                   <div className="py-8 flex flex-col items-center">
                      <div className="w-16 h-16 bg-green-100 dark:bg-green-900/30 rounded-full flex items-center justify-center text-green-600 dark:text-green-400 mb-4 animate-bounce">
                        <CheckCircle size={32} />
                      </div>
                      <h4 className="text-lg font-bold text-slate-800 dark:text-white">Enrollment Successful</h4>
                      <p className="text-sm text-slate-500 dark:text-slate-400 text-center mt-2">
                        Employee biometrics have been securely linked to their profile.
                      </p>
                      <button 
                        onClick={closeBiometricModal}
                        className="mt-6 w-full py-2 bg-slate-900 dark:bg-slate-700 text-white rounded-lg hover:bg-slate-800 dark:hover:bg-slate-600"
                      >
                        Close
                      </button>
                   </div>
                 )}
               </div>

               {biometricStep === 'start' && (
                 <button onClick={closeBiometricModal} className="absolute top-4 right-4 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200">
                   <X size={20} />
                 </button>
               )}
            </div>
         </div>
      )}
    </div>
  );
};

export default EmployeeManager;

import React, { useState, useRef, useEffect } from 'react';
import { Employee, PayrollRun } from '../types';
import { Download, AlertCircle, CheckCircle, Wallet, Calendar, ChevronRight, X, Lock, LogIn, LogOut, ScanFace, Camera, Loader2, UserCheck } from 'lucide-react';
import { generatePayslipPDF } from '../services/exportUtils';

interface EmployeePortalProps {
  employees: Employee[];
  payrollRuns: PayrollRun[];
}

const EmployeePortal: React.FC<EmployeePortalProps> = ({ employees, payrollRuns }) => {
  const [currentUser, setCurrentUser] = useState<Employee | null>(null);
  const [emailInput, setEmailInput] = useState('');
  const [loginError, setLoginError] = useState('');

  // Login Flow State
  const [loginStep, setLoginStep] = useState<'email' | 'face'>('email');
  const [pendingUser, setPendingUser] = useState<Employee | null>(null);

  // Biometric State
  const videoRef = useRef<HTMLVideoElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [isVerifying, setIsVerifying] = useState(false);

  const [showIssueModal, setShowIssueModal] = useState(false);
  const [issueText, setIssueText] = useState('');

  // Fix: Attach stream to video element whenever step becomes 'face' and stream is available
  useEffect(() => {
    if (loginStep === 'face' && stream && videoRef.current) {
      videoRef.current.srcObject = stream;
    }
  }, [loginStep, stream]);

  // Cleanup stream on unmount
  useEffect(() => {
    return () => {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, []);

  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({ video: true });
      setStream(mediaStream);
    } catch (err) {
      console.error(err);
      setLoginError("Camera access required for verification.");
      setLoginStep('email');
    }
  };

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
  };

  const handleEmailSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoginError('');

    const user = employees.find(emp => emp.email.toLowerCase() === emailInput.trim().toLowerCase());

    if (user) {
      if (user.status === 'Resigned' || user.status === 'Suspended') {
           setLoginError('Access restricted. Please contact HR.');
           return;
      }
      // Found user, move to face verification
      setPendingUser(user);
      setLoginStep('face');
      await startCamera();
    } else {
      setLoginError('Email not found in employee records.');
    }
  };

  const verifyFace = () => {
    setIsVerifying(true);

    // Simulate biometric matching delay
    setTimeout(() => {
        stopCamera();
        setIsVerifying(false);
        if (pendingUser) {
            setCurrentUser(pendingUser);
            setPendingUser(null);
            setLoginStep('email'); // Reset for next time
        }
    }, 2000);
  };

  const cancelLogin = () => {
      stopCamera();
      setLoginStep('email');
      setPendingUser(null);
      setLoginError('');
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setEmailInput('');
    setLoginError('');
    setLoginStep('email');
  };

  if (!currentUser) {
    return (
      <div className="h-screen flex items-center justify-center bg-slate-50 dark:bg-slate-900 p-6">
        <div className="w-full max-w-md bg-white dark:bg-slate-800 rounded-2xl shadow-xl p-8 border border-slate-100 dark:border-slate-700">

          {loginStep === 'email' ? (
            <>
                <div className="text-center mb-8">
                    <div className="w-16 h-16 bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 rounded-full flex items-center justify-center mx-auto mb-4">
                    <Lock size={32} />
                    </div>
                    <h2 className="text-2xl font-bold text-slate-800 dark:text-white">Employee Portal</h2>
                    <p className="text-slate-500 dark:text-slate-400 mt-2">Secure access to your payslips.</p>
                </div>

                <form onSubmit={handleEmailSubmit} className="space-y-4">
                    <div>
                    <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">Work Email</label>
                    <input 
                        type="email" 
                        required
                        className="w-full border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-700 text-slate-900 dark:text-white rounded-lg px-4 py-3 focus:ring-2 focus:ring-blue-500 focus:outline-none transition"
                        placeholder="name@company.com"
                        value={emailInput}
                        onChange={(e) => setEmailInput(e.target.value)}
                    />
                    </div>

                    {loginError && (
                    <div className="flex items-center gap-2 text-sm text-red-600 dark:text-red-400 bg-red-50 dark:bg-red-900/20 p-3 rounded-lg">
                        <AlertCircle size={16} />
                        {loginError}
                    </div>
                    )}

                    <button 
                    type="submit"
                    className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 rounded-lg shadow-lg shadow-blue-200 dark:shadow-blue-900/50 transition flex items-center justify-center gap-2"
                    >
                    <LogIn size={20} /> Next
                    </button>
                </form>
            </>
          ) : (
            // Face Verification Step
            <div className="text-center animate-in fade-in slide-in-from-bottom-4 duration-300">
