                      <span className="font-medium dark:text-slate-200">₦{latestPay?.entry.transport.toLocaleString() || '0'}</span>
                    </div>
                 </div>
                 <div>
                    <div className="text-xs text-slate-400 dark:text-slate-500 uppercase font-semibold mb-1">Deductions</div>
