const App: React.FC = () => {
  const [currentView, setCurrentView] = useState('dashboard');
  const [darkMode, setDarkMode] = useState(false);

  // Use useMemo so we don't regenerate 250 employees on every render
  const { employees: initialEmployees, payrollRuns: initialRuns } = useMemo(() => generateDummyData(), []);

  const [employees, setEmployees] = useState<Employee[]>(initialEmployees);
  const [payrollRuns, setPayrollRuns] = useState<PayrollRun[]>(initialRuns);
  const [auditLogs, setAuditLogs] = useState<AuditLogEntry[]>(INITIAL_AUDIT_LOGS);

  // Effect to toggle body class
  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  const toggleDarkMode = () => {
    setDarkMode(!darkMode);
  };

  const addAuditLog = (action: string, details: string, category: AuditLogEntry['category']) => {
    const newLog: AuditLogEntry = {
        id: crypto.randomUUID(),
        timestamp: new Date().toISOString(),
        user: 'Mr. Adebayo', // Hardcoded for demo
        action,
        details,
        category
    };
    setAuditLogs(prev => [newLog, ...prev]);
  };

  const renderContent = () => {
    switch (currentView) {
      case 'dashboard':
        return <Dashboard employees={employees} payrollRuns={payrollRuns} />;
      case 'employees':
        return <EmployeeManager employees={employees} setEmployees={setEmployees} addAuditLog={addAuditLog} />;
      case 'payroll':
        return <PayrollProcessor employees={employees} payrollRuns={payrollRuns} setPayrollRuns={setPayrollRuns} addAuditLog={addAuditLog} />;
      case 'forecasting':
        return <Forecasting employees={employees} payrollRuns={payrollRuns} />;
      case 'reports':
        return <Reports payrollRuns={payrollRuns} employees={employees} />;
      case 'audit':
        return <GeminiAudit payrollRuns={payrollRuns} />;
      case 'audit-logs':
        return <AuditLogViewer logs={auditLogs} />;
      case 'portal':
        return <EmployeePortal employees={employees} payrollRuns={payrollRuns} />;
      default:
        return <Dashboard employees={employees} payrollRuns={payrollRuns} />;
    }
  };

  return (
    <div className={`flex h-screen bg-slate-50 dark:bg-slate-900 transition-colors duration-200`}>
      <Sidebar 
        currentView={currentView} 
        setCurrentView={setCurrentView} 
        isDarkMode={darkMode} 
        toggleDarkMode={toggleDarkMode} 
      />
      <main className="flex-1 ml-64 h-full overflow-hidden">
        {renderContent()}
      </main>
    </div>
  );
};

